  // Function to add master file - loads original clean master file from project as new mother
  const addMasterFile = async () => {
    console.log('🔍 Add Master File button clicked');

    if (!isProjectMode) {
      alert('❌ Add Master File is only available in Project Mode');
      return;
    }

    try {
      // Get current project data
      const currentData = data || webCreationData;
      if (!currentData) {
        alert('❌ No project data available');
        return;
      }

      // Use the current project's master file template (first mother as clean template)
      const currentMotherObjects = currentData.objects.filter(obj => obj.type?.includes('mother'));
      if (currentMotherObjects.length === 0) {
        alert('❌ No mother objects found in current project');
        return;
      }

      // Use the first mother as the master template (this is the original design)
      const masterTemplate = currentMotherObjects[0];
      console.log('🎯 Using current project master template:', masterTemplate.name);

      // Find next mother number for current canvas
      const nextMotherNumber = currentMotherObjects.length + 1;

      // Create clean regions from original master file (no slits, original design)
      const originalRegions = (masterTemplate as any).regions || [];
      const cleanRegions = originalRegions.map((region: any) => ({
        ...region,
        id: `${region.id}_master_${nextMotherNumber}`, // Unique ID for master file region
        content: region.content || [], // Keep original content structure but empty
        children: [] // No slits - clean master file
      }));

      console.log('🧹 Created clean master regions:', cleanRegions.length);

      // Calculate position for new mother next to latest mother
      const spacing = 20;
      let maxRightX = 0;
      currentMotherObjects.forEach(mother => {
        const rightEdge = mother.x + mother.width;
        if (rightEdge > maxRightX) {
          maxRightX = rightEdge;
        }
      });

      const newX = maxRightX + spacing;
      const newY = masterTemplate.y;

      // Create new mother from original master file template
      const masterFileMother: AIObject = {
        name: `Mother_${nextMotherNumber}`,
        type: 'mother',
        x: newX,
        y: newY,
        width: masterTemplate.width,
        height: masterTemplate.height,
        typename: 'mother',
        // Use original master file properties
        margins: (masterTemplate as any).margins,
        sewingPosition: (masterTemplate as any).sewingPosition,
        sewingOffset: (masterTemplate as any).sewingOffset,
        midFoldLine: (masterTemplate as any).midFoldLine,
        regions: cleanRegions // Original clean regions from master file
      } as any;

      console.log('📁 New master file mother created:', masterFileMother);

      // Add to current canvas objects (keep existing content)
      const updatedObjects = [...currentData.objects, masterFileMother];

      // Create new data structure
      const updatedData = {
        ...currentData,
        objects: updatedObjects,
        totalObjects: updatedObjects.length
      };

      // Update state
      setData(updatedData);
      if (webCreationData) {
        setWebCreationData(updatedData);
      }

      // Select the new master file mother
      setSelectedObject(masterFileMother);

      // Show success notification
      setNotification(`✅ Original master file added as ${masterFileMother.name} (${cleanRegions.length} clean regions)`);
      setTimeout(() => setNotification(null), 3000);

      console.log('✅ Original master file added successfully');

    } catch (error) {
      console.error('❌ Error adding master file:', error);
      alert('❌ Error adding master file. Please try again.');
    }
  };

  // Capture canvas as image for multi-page PDF generation
  const captureCanvasImage = async () => {
    try {
      console.log('📸 Starting canvas image capture...');

      const svgElement = document.querySelector('svg') as SVGElement;
      if (!svgElement) {
        throw new Error('SVG element not found');
      }

      // Wait for content to render
      await new Promise(resolve => setTimeout(resolve, 2000));

      // Get SVG viewport dimensions
      const svgRect = svgElement.getBoundingClientRect();
      const svgWidth = svgRect.width;
      const svgHeight = svgRect.height;

      console.log('📐 SVG dimensions:', { width: svgWidth, height: svgHeight });

      // Create canvas for capture
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) {
        throw new Error('Canvas context not available');
      }

      // Set high resolution
      const scale = 3;
      canvas.width = svgWidth * scale;
      canvas.height = svgHeight * scale;
      ctx.scale(scale, scale);
      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';

      // Clone SVG and inline styles
      const svgClone = svgElement.cloneNode(true) as SVGElement;
      const inlineAllStyles = (element: Element) => {
        if (element instanceof HTMLElement || element instanceof SVGElement) {
          const computedStyle = window.getComputedStyle(element);
          const importantProps = ['font-family', 'font-size', 'font-weight', 'fill', 'stroke', 'stroke-width', 'color', 'text-anchor', 'dominant-baseline', 'opacity'];
          let cssText = '';
          importantProps.forEach(prop => {
            const value = computedStyle.getPropertyValue(prop);
            if (value) cssText += `${prop}: ${value}; `;
          });
          if (cssText) {
            element.setAttribute('style', (element.getAttribute('style') || '') + cssText);
          }
        }
        Array.from(element.children).forEach(child => inlineAllStyles(child));
      };
      inlineAllStyles(svgClone);

      // Serialize SVG
      const serializer = new XMLSerializer();
      const svgData = serializer.serializeToString(svgClone);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const svgUrl = URL.createObjectURL(svgBlob);

      // Create image from SVG
      const img = new Image();
      const imageLoadPromise = new Promise<string>((resolve, reject) => {
        img.onload = () => {
          try {
            // Draw to canvas
            ctx.fillStyle = 'white';
            ctx.fillRect(0, 0, svgWidth, svgHeight);
            ctx.drawImage(img, 0, 0, svgWidth, svgHeight);

            // Convert to data URL
            const imageData = canvas.toDataURL('image/png', 1.0);
            URL.revokeObjectURL(svgUrl);

            console.log('✅ Canvas image captured successfully');
            resolve(imageData);
          } catch (error) {
            reject(error);
          }
        };
        img.onerror = () => reject(new Error('Failed to load SVG image'));
      });

      img.src = svgUrl;
      const imageData = await imageLoadPromise;

      // Send image data back to parent window
      window.parent.postMessage({
        type: 'IMAGE_CAPTURED',
        imageData: imageData,
        width: canvas.width,
        height: canvas.height
      }, '*');

      console.log('📤 Image data sent to parent window');

    } catch (error) {
      console.error('❌ Error capturing canvas image:', error);
      window.parent.postMessage({
        type: 'CAPTURE_ERROR',
        error: error instanceof Error ? error.message : 'Unknown error'
      }, '*');
    }
  };

  // Function to generate PDF with all mothers
  const generatePDFAllMothers = async () => {
    // Initialize debug log collection for easy export (same as canvas PDF)
    const debugLogs: string[] = [];
    const logExport = (message: string, data?: any) => {
      const timestamp = new Date().toISOString();
      const logEntry = `[${timestamp}] ${message}${data ? ' | ' + JSON.stringify(data, null, 2) : ''}`;
      debugLogs.push(logEntry);
      console.log(message, data || '');
    };

    // Function to export all logs at once for easy copying
    const exportAllLogs = () => {
      const allLogs = debugLogs.join('\n');
      console.log('\n' + '='.repeat(80));
      console.log('📋 PRINT-AS-PDF DEBUG LOGS - COPY BELOW FOR ANALYSIS');
      console.log('='.repeat(80));
      console.log(allLogs);
      console.log('='.repeat(80));
      console.log('📋 END OF LOGS - COPY ABOVE FOR ANALYSIS');
      console.log('='.repeat(80) + '\n');

      // Also make logs available on window for easy access
      (window as any).printPdfDebugLogs = allLogs;
      console.log('💾 Logs also saved to window.printPdfDebugLogs for easy copying');
    };

    const currentData = data || webCreationData;
    if (!currentData) {
      logExport('❌ No data to generate PDF');
      alert('❌ No data to generate PDF');
      exportAllLogs();
      return;
    }

    let mothers = currentData.objects.filter(obj => obj.type?.includes('mother'));
    if (mothers.length === 0) {
      alert('❌ No mothers found to generate PDF');
      return;
    }

    // Sort mothers to keep parent-child relationships together
    console.log('DEBUG: Checking mother properties before sorting...');
    mothers.forEach(m => {
      console.log(`  ${m.name}:`, {
        x: m.x,
        isOverflowChild: (m as any).isOverflowChild,
        parentMotherId: (m as any).parentMotherId,
        childMotherIds: (m as any).childMotherIds
      });
    });

    // Separate parent mothers from child mothers
    const parentMothers = mothers.filter(m => !(m as any).isOverflowChild);
    const childMothers = mothers.filter(m => (m as any).isOverflowChild);

    console.log(`PARENTS: ${parentMothers.map(m => m.name).join(', ')}`);
    console.log(`CHILDREN: ${childMothers.map(m => m.name).join(', ')}`);

    // Sort parent mothers by x position (left to right)
    parentMothers.sort((a, b) => a.x - b.x);

    console.log(`PARENTS_SORTED_BY_X: ${parentMothers.map(m => `${m.name}(x=${m.x})`).join(', ')}`);

    // Build final sorted array: insert children immediately after their parent
    const sortedMothers: AIObject[] = [];
    const addedChildNames = new Set<string>(); // Track added children to avoid duplicates

    parentMothers.forEach(parent => {
      // Add the parent
      sortedMothers.push(parent);
      console.log(`ADDED_PARENT: ${parent.name}`);

      // Find and add all children of this parent (in creation order)
      const parentChildIds = (parent as any).childMotherIds || [];
      if (parentChildIds.length > 0) {
        console.log(`  PARENT_HAS_CHILDREN: ${parent.name} -> ${parentChildIds.join(', ')}`);
      }

      parentChildIds.forEach((childId: string) => {
        // Skip if already added (avoid duplicates)
        if (addedChildNames.has(childId)) {
          console.log(`  SKIP_DUPLICATE_CHILD: ${childId}`);
          return;
        }

        const child = childMothers.find(c => c.name === childId);
        if (child) {
          sortedMothers.push(child);
          addedChildNames.add(childId);
          console.log(`  ADDED_CHILD: ${child.name}`);
        } else {
          console.log(`  CHILD_NOT_FOUND: ${childId}`);
        }
      });
    });

    // Add any remaining child mothers that weren't linked to a parent
    // This handles cases where composition translation creates overflow children
    // but the parent-child relationship isn't properly established
    const orphanChildren = childMothers.filter(child => !addedChildNames.has(child.name));
    if (orphanChildren.length > 0) {
      console.log(`ORPHAN_CHILDREN_FOUND: ${orphanChildren.map(m => m.name).join(', ')}`);
      orphanChildren.forEach(orphan => {
        sortedMothers.push(orphan);
        console.log(`  ADDED_ORPHAN_CHILD: ${orphan.name}`);
      });
    }

    console.log(`FINAL_ORDER: ${sortedMothers.map(m => m.name).join(', ')}`);
    console.log(`FINAL_COUNT: ${sortedMothers.length} (was ${mothers.length} before sorting)`);

    // Replace mothers array with sorted version
    mothers = sortedMothers;

    // Simple confirmation dialog (skip in order preview mode)
    const urlParams = new URLSearchParams(window.location.search);
    const isOrderPreview = urlParams.get('autoGeneratePDF') === 'true';

    if (!isOrderPreview) {
      const confirmed = window.confirm(`🖨️ Generate PDF with layout and content information?\n\n📊 Mothers: ${mothers.length}\n📋 Mode: ${isProjectMode ? 'Project Mode' : 'Master File Mode'}\n\n📄 PDF will include:\n• Mother outlines and margins\n• Regions and slices\n• Content types\n• Mid fold lines and padding\n\nContinue?`);

      if (!confirmed) {
        return;
      }
    }

    console.log('🖨️ Generating PDF for all mothers:', mothers.length);

    // Calculate total dimensions needed for all mothers
    let maxWidth = 0;
    let totalHeight = 0;

    mothers.forEach((mother, index) => {
      maxWidth = Math.max(maxWidth, mother.x + mother.width);
      totalHeight = Math.max(totalHeight, mother.y + mother.height);
    });

    // Add proper margins (minimum 10mm on all sides) + header space
    const margin = 20; // 10mm on each side
    const headerSpace = 40; // Reduced space needed for header (no hierarchy section)
    const contentWidthMM = maxWidth;
    const contentHeightMM = totalHeight;
    const totalWidthMM = contentWidthMM + margin;
    const totalHeightMM = contentHeightMM + margin + headerSpace; // Include header space

    console.log('📐 PDF Dimensions Debug:', {
      contentWidthMM,
      contentHeightMM,
      margin,
      headerSpace,
      totalWidthMM,
      totalHeightMM,
      breakdown: {
        contentHeight: contentHeightMM,
        margins: margin,
        header: headerSpace,
        total: totalHeightMM
      },
      mothersCount: mothers.length,
      motherPositions: mothers.map(m => ({ name: m.name, x: m.x, y: m.y, width: m.width, height: m.height, bottom: m.y + m.height }))
    });

    // Paper size options (base sizes only)
    const basePaperSizes = [
      { name: 'A4', width: 210, height: 297 },
      { name: 'A3', width: 297, height: 420 },
      { name: 'A2', width: 420, height: 594 },
      { name: 'A1', width: 594, height: 841 }
    ];

    // Generate both portrait and landscape options for each size
    const paperOptions: Array<{
      name: string;
      width: number;
      height: number;
      orientation: 'portrait' | 'landscape';
    }> = [];

    basePaperSizes.forEach(size => {
      // Portrait
      paperOptions.push({
        name: size.name,
        width: size.width,
        height: size.height,
        orientation: 'portrait'
      });
      // Landscape
      paperOptions.push({
        name: size.name + 'L',
        width: size.height,
        height: size.width,
        orientation: 'landscape'
      });
    });

    // Find the optimal paper size and orientation based on area utilization
    let bestOption = null;
    let bestUtilization = 0;

    console.log('🔍 Testing paper options for content:', { totalWidthMM, totalHeightMM });

    for (const option of paperOptions) {
      // Check if content fits with margins
      const fitsWidth = totalWidthMM <= option.width;
      const fitsHeight = totalHeightMM <= option.height;
      const fits = fitsWidth && fitsHeight;

      if (fits) {
        // Calculate area utilization percentage (content area / paper area)
        const contentArea = totalWidthMM * totalHeightMM;
        const paperArea = option.width * option.height;
        const utilization = contentArea / paperArea;

        console.log(`📄 ${option.name}: ${option.width}×${option.height}mm (${option.orientation}) - Utilization: ${(utilization * 100).toFixed(1)}%`);

        if (utilization > bestUtilization) {
          bestUtilization = utilization;
          bestOption = option;
        }
      } else {
        console.log(`❌ ${option.name}: ${option.width}×${option.height}mm - TOO SMALL (needs ${totalWidthMM}×${totalHeightMM}mm)`);
      }
    }

    // Fallback to largest size if nothing fits
    if (!bestOption) {
      bestOption = paperOptions[paperOptions.length - 1]; // A1 Landscape
      console.warn('⚠️ Content too large for standard paper sizes, using A1 Landscape');
      bestUtilization = (totalWidthMM * totalHeightMM) / (bestOption.width * bestOption.height);
    }

    const paperSize = bestOption.name;
    const paperWidthMM = bestOption.width;
    const paperHeightMM = bestOption.height;
    const orientation = bestOption.orientation;

    console.log(`📄 OPTIMAL PAPER SELECTION:`, {
      paperSize,
      dimensions: `${paperWidthMM}×${paperHeightMM}mm`,
      orientation,
      utilization: `${(bestUtilization * 100).toFixed(1)}%`,
      contentArea: `${totalWidthMM}×${totalHeightMM}mm`,
      paperArea: `${paperWidthMM}×${paperHeightMM}mm`,
      contentFits: totalWidthMM <= paperWidthMM && totalHeightMM <= paperHeightMM,
      marginLeft: (paperWidthMM - totalWidthMM) / 2,
      marginTop: (paperHeightMM - totalHeightMM) / 2
    });

    // Generate PDF with paper size info
    const pdfData = {
      ...currentData,
      paperSize: paperSize,
      paperDimensions: `${paperWidthMM}cm × ${paperHeightMM/10}cm`,
      motherCount: mothers.length
    };

    // Generate single PDF with all mothers using jsPDF
    try {
      const { jsPDF } = require('jspdf');

      // Create PDF with optimized paper size and orientation
      const pdf = new jsPDF({
        orientation: orientation,
        unit: 'mm',
        format: [paperWidthMM, paperHeightMM]
      });

      // Try to embed Wash Care Symbols M54 font for washing care symbols
      const fontEmbedded = await embedWashCareFont(pdf);
      if (fontEmbedded) {
        // console.log('✅ Font embedded successfully for PDF generation');
      } else {
        // console.log('⚠️ Font embedding failed, will use canvas rendering and fallback shapes');
      }

      // Get order information from sessionStorage if in order preview mode
      let orderInfo: any = null;
      if (isOrderPreview) {
        const orderDataStr = sessionStorage.getItem('__order_preview_data__');
        if (orderDataStr) {
          orderInfo = JSON.parse(orderDataStr);
        }
      }

      // Add header information
      pdf.setFont('helvetica', 'normal'); // Ensure Arial font for header

      if (isOrderPreview && orderInfo) {
        // Order preview mode - show customer and order information
        const customerName = orderInfo.customerName || 'N/A';
        const orderNumber = orderInfo.orderNumber || orderInfo.userOrderNumber || 'N/A';
        const projectSlug = orderInfo.projectSlug || '';
        const layoutId = orderInfo.layoutId || '';
        const layoutName = (currentData as any).name || 'Layout';

        // Get actual dimensions from design data (same logic as Master Files Management)
        let layoutWidth = 0;
        let layoutHeight = 0;

        if (currentData?.objects && Array.isArray(currentData.objects) && currentData.objects.length > 0) {
          // Find the largest object (usually the mother)
          const objects = currentData.objects;
          let largestObject = objects[0];
          let maxArea = largestObject.width * largestObject.height;

          objects.forEach((obj: any) => {
            const area = obj.width * obj.height;
            if (area > maxArea) {
              maxArea = area;
              largestObject = obj;
            }
          });

          layoutWidth = largestObject.width;
          layoutHeight = largestObject.height;
        }

        pdf.setFontSize(10);
        let yPos = 10;

        pdf.text(`Customer: ${customerName}`, 10, yPos);
        yPos += 5;

        pdf.text(`Order #: PO: ${orderNumber}`, 10, yPos);
        yPos += 5;

        pdf.text(`${projectSlug} - ${layoutId} - ${layoutName} - ${mothers.length} pages`, 10, yPos);
        yPos += 5;

        // Add variable component information
        const currentLine = orderInfo.currentLine || (orderInfo.orderLines && orderInfo.orderLines.length > 0 ? orderInfo.orderLines[0] : null);
        const componentVariables = currentLine?.componentVariables || orderInfo.variableData;

        if (componentVariables) {
          // Available languages for translation
          const availableLanguages = [
            { code: 'ES', name: 'Spanish' },
            { code: 'FR', name: 'French' },
            { code: 'EN', name: 'English' },
            { code: 'PT', name: 'Portuguese' },
            { code: 'DU', name: 'Dutch' },
            { code: 'IT', name: 'Italian' },
            { code: 'GR', name: 'Greek' },
            { code: 'JA', name: 'Japanese' },
            { code: 'DE', name: 'German' },
            { code: 'DA', name: 'Danish' },
            { code: 'SL', name: 'Slovenian' },
            { code: 'CH', name: 'Chinese' },
            { code: 'KO', name: 'Korean' },
            { code: 'ID', name: 'Indonesian' },
            { code: 'AR', name: 'Arabic' },
            { code: 'GA', name: 'Galician' },
            { code: 'CA', name: 'Catalan' },
            { code: 'BS', name: 'Basque' }
          ];

          // Iterate through component variables
          Object.entries(componentVariables).forEach(([componentId, componentData]: [string, any]) => {
            if (componentData.type === 'comp-trans') {
              // Get remark from layout configuration
              let remarkText: string | string[] = '';
              try {
                const storageKey = `project_${projectSlug}_layouts`;
                const savedLayouts = localStorage.getItem(storageKey);
                if (savedLayouts) {
                  const parsedLayouts = JSON.parse(savedLayouts);
                  const layout = parsedLayouts.find((l: any) => l.id === layoutId);
                  if (layout?.canvasData?.objects) {
                    // Extract component configuration from layout
                    const match = componentId.match(/^(.+)_content_(\d+)$/);
                    if (match) {
                      const regionId = match[1];
                      const contentIndex = parseInt(match[2], 10);

                      for (const obj of layout.canvasData.objects) {
                        if (obj.regions && Array.isArray(obj.regions)) {
                          const region = obj.regions.find((r: any) => r.id === regionId);
                          if (region && layout.regionContents?.[regionId]) {
                            const contents = layout.regionContents[regionId];
                            const content = contents[contentIndex];
                            if (content?.newCompTransConfig) {
                              // Get selected languages and sequence
                              const selectedLanguages = content.newCompTransConfig.selectedLanguages || [];
                              const languageSequence = content.newCompTransConfig.languageSequence || {};

                              // Sort languages by selection sequence
                              const sortedLangs = [...selectedLanguages].sort((a, b) => {
                                const seqA = languageSequence[a] || 0;
                                const seqB = languageSequence[b] || 0;
                                return seqA - seqB;
                              });

                              // Format as "CODE LanguageName (sequence)"
                              const formattedLangs = sortedLangs.map(code => {
                                const lang = availableLanguages.find(l => l.code === code);
                                const seq = languageSequence[code] || '';
                                return lang ? `${lang.code} ${lang.name} (${seq})` : code;
                              });

                              // Break into groups of 9 languages per line
                              const langsPerLine = 9;
                              const langGroups: string[] = [];
                              for (let i = 0; i < formattedLangs.length; i += langsPerLine) {
                                const group = formattedLangs.slice(i, i + langsPerLine);
                                langGroups.push(group.join(', '));
                              }

                              // Store groups for multi-line rendering
                              remarkText = langGroups;
                            }
                          }
                        }
                      }
                    }
                  }
                }
              } catch (error) {
                console.error('Error getting composition translation info from layout:', error);
              }

              // Handle multi-line text for composition translation
              if (Array.isArray(remarkText)) {
                // Reduce font size by 30% for composition translation
                const originalFontSize = 10;
                const reducedFontSize = originalFontSize * 0.7; // 70% of original
                pdf.setFontSize(reducedFontSize);

                // Render first line with opening bracket
                pdf.text(`Composition Translation - {(${remarkText[0]}${remarkText.length > 1 ? ',' : ')'}}`, 10, yPos);
                yPos += 4; // Slightly reduced spacing for smaller font

                // Render middle lines with proper indentation
                for (let i = 1; i < remarkText.length; i++) {
                  const isLastLine = i === remarkText.length - 1;
                  pdf.text(`  ${remarkText[i]}${isLastLine ? ')}' : ','}`, 10, yPos);
                  yPos += 4; // Slightly reduced spacing for smaller font
                }

                // Restore original font size
                pdf.setFontSize(originalFontSize);
              } else {
                // Fallback for when remarkText is a string
                pdf.text(`Composition Translation${remarkText}`, 10, yPos);
                yPos += 5;
              }
            } else if (componentData.type === 'multi-line') {
              // Get remark from layout configuration
              let remarkText = '';
              try {
                const storageKey = `project_${projectSlug}_layouts`;
                const savedLayouts = localStorage.getItem(storageKey);
                if (savedLayouts) {
                  const parsedLayouts = JSON.parse(savedLayouts);
                  const layout = parsedLayouts.find((l: any) => l.id === layoutId);
                  if (layout?.canvasData?.objects) {
                    // Extract component configuration from layout
                    const match = componentId.match(/^(.+)_content_(\d+)$/);
                    if (match) {
                      const regionId = match[1];
                      const contentIndex = parseInt(match[2], 10);

                      for (const obj of layout.canvasData.objects) {
                        if (obj.regions && Array.isArray(obj.regions)) {
                          const region = obj.regions.find((r: any) => r.id === regionId);
                          if (region && layout.regionContents?.[regionId]) {
                            const contents = layout.regionContents[regionId];
                            const content = contents[contentIndex];
                            if (content?.newMultiLineConfig?.variableRemark) {
                              remarkText = ` (${content.newMultiLineConfig.variableRemark})`;
                            }
                          }
                        }
                      }
                    }
                  }
                }
              } catch (error) {
                console.error('Error getting multi-line remark from layout:', error);
              }

              pdf.text(`Multi-line Text${remarkText}`, 10, yPos);
              yPos += 5;
            }
          });
        }

        const now = new Date();
        const dateStr = `${now.getFullYear()}/${(now.getMonth() + 1).toString().padStart(2, '0')}/${now.getDate().toString().padStart(2, '0')} ${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}:${now.getSeconds().toString().padStart(2, '0')}`;
        pdf.text(`Layout Generated: ${dateStr}`, 10, yPos);
        yPos += 5;

        pdf.text(`Layout Size: ${layoutWidth} X ${layoutHeight}`, 10, yPos);
        yPos += 5;

        pdf.setFontSize(8);
        const currentDate = now.toLocaleDateString();
        pdf.text(`PDF Generated by Care Label Layout System v${packageJson.version} - ${currentDate}`, 10, yPos);
        yPos += 5;

        // Add layout number if available
        const layoutNumber = (orderInfo.currentLineIndex !== undefined) ? orderInfo.currentLineIndex + 1 : 1;
        pdf.setFontSize(10);
        pdf.text(`layout ${layoutNumber}`, 10, yPos);
      } else {
        // Manual PDF generation - show original header
        pdf.setFontSize(16);
        const titleText = isProjectMode ? `Project: All Content (${mothers.length} mothers)` : `Master File: All Mothers (${mothers.length})`;
        pdf.text(titleText, 10, 15);
        pdf.setFontSize(10);
        pdf.text(`Paper Size: ${paperSize} (${paperWidthMM/10}cm × ${paperHeightMM/10}cm)`, 10, 25);

        // Add version information
        pdf.setFontSize(8);
        const currentDate = new Date().toLocaleDateString();
        pdf.text(`Generated by Care Label Layout System v${packageJson.version} - ${currentDate}`, 10, 32);
        pdf.text(`Generated: ${new Date().toLocaleString()}`, 10, 30);
      }

      // Start content immediately after header (no hierarchy section)
      let currentY = isOrderPreview && orderInfo ? 45 : 40; // Start position for content (extra space for layout number in order preview)

      // Calculate content offset with proper margins and ensure no cutting
      const minMargin = 10; // Minimum 10mm margin on all sides
      const availableWidth = paperWidthMM - (2 * minMargin);
      const availableHeight = paperHeightMM - currentY - (2 * minMargin); // Account for header space and margins

      // Check if content fits in available space
      const contentFitsWidth = contentWidthMM <= availableWidth;
      const contentFitsHeight = contentHeightMM <= availableHeight;

      if (!contentFitsWidth || !contentFitsHeight) {
        console.warn('⚠️ CONTENT TOO LARGE FOR SELECTED PAPER SIZE!', {
          contentSize: `${contentWidthMM}×${contentHeightMM}mm`,
          availableSpace: `${availableWidth}×${availableHeight}mm`,
          paperSize: `${paperWidthMM}×${paperHeightMM}mm`,
          headerSpace: currentY,
          fitsWidth: contentFitsWidth,
          fitsHeight: contentFitsHeight
        });
      }

      // Position content with proper margins (don't center if it causes cutting)
      const contentOffsetX = minMargin;
      const contentOffsetY = currentY + minMargin;

      console.log('📐 Content positioning (SAFE):', {
        paperSize: `${paperWidthMM}×${paperHeightMM}mm`,
        contentSize: `${contentWidthMM}×${contentHeightMM}mm`,
        headerSpace: currentY,
        availableSpace: `${availableWidth}×${availableHeight}mm`,
        offset: `${contentOffsetX.toFixed(1)}, ${contentOffsetY.toFixed(1)}mm`,
        margins: {
          left: `${minMargin}mm`,
          right: `${(paperWidthMM - contentWidthMM - minMargin).toFixed(1)}mm`,
          top: `${minMargin}mm`,
          bottom: `${(paperHeightMM - currentY - contentHeightMM - minMargin).toFixed(1)}mm`
        },
        contentFits: contentFitsWidth && contentFitsHeight
      });

      // Calculate total width needed for all mothers in sequential layout
      const spacing = 10; // 10mm spacing between mothers
      let totalSequentialWidth = 0;
      mothers.forEach((mother, idx) => {
        totalSequentialWidth += mother.width;
        if (idx < mothers.length - 1) {
          totalSequentialWidth += spacing;
        }
      });

      console.log(`TOTAL_SEQUENTIAL_WIDTH: ${totalSequentialWidth}mm`);
      console.log(`PAPER_WIDTH: ${paperWidthMM}mm`);

      // Center the mothers horizontally on the page
      const horizontalCenterOffset = (paperWidthMM - totalSequentialWidth) / 2;
      console.log(`HORIZONTAL_CENTER_OFFSET: ${horizontalCenterOffset}mm`);

      // Draw each mother and its regions
      // Calculate sequential X positions for sorted mothers
      let sequentialX = horizontalCenterOffset;

      mothers.forEach((mother, motherIndex) => {
        const motherRegions = (mother as any).regions || [];

        // Use sequential X position instead of canvas X position
        // This ensures sorted order (parent followed by children)
        const motherX = sequentialX;
        const motherY = mother.y + contentOffsetY;

        console.log(`RENDERING: ${mother.name} at x=${motherX} (original x=${mother.x})`);

        // Update sequential X for next mother (with spacing)
        sequentialX += mother.width + spacing;

        // Draw mother outline
        pdf.setDrawColor(0, 0, 0); // Black
        pdf.setLineWidth(0.3); // Standard thickness
        pdf.rect(motherX, motherY, mother.width, mother.height);

        // Add mother label
        pdf.setFont('helvetica', 'normal'); // Ensure Arial/Helvetica font for mother labels
        pdf.setFontSize(8);
        pdf.setTextColor(0, 0, 0); // Black text
        // Show dimensions only if dimensions toggle is enabled
        const motherDimensionText = showDimensions ? ` (${mother.width}×${mother.height}mm)` : '';
        pdf.text(`${mother.name}${motherDimensionText}`, motherX, motherY - 3);

        // Draw mother solid border (black) - matching your image
        pdf.setDrawColor(0, 0, 0); // Black solid border
        pdf.setLineWidth(0.5); // Standard line thickness
        pdf.setLineDashPattern([], 0); // Solid line
        pdf.rect(motherX, motherY, mother.width, mother.height);

        // Draw sewing position lines if sewing lines are enabled (and not in only preview mode)
        if (showSewingLines && !onlyPreview) {
          const objectSewingPosition = (mother as any).sewingPosition || 'top';
          const objectSewingOffset = (mother as any).sewingOffset || 5;
          const objectMidFoldLine = (mother as any).midFoldLine;

          // Only draw sewing lines if mid-fold is not enabled
          if (!objectMidFoldLine || !objectMidFoldLine.enabled) {
            // Set red color for sewing lines
            pdf.setDrawColor(211, 47, 47); // Red color (#d32f2f)
            pdf.setLineWidth(0.3);
            pdf.setLineDashPattern([2, 2], 0); // Dashed line

            switch (objectSewingPosition) {
              case 'top':
                // Draw horizontal line at offset from top
                pdf.line(motherX, motherY + objectSewingOffset, motherX + mother.width, motherY + objectSewingOffset);
                // Add dimension text
                pdf.setTextColor(211, 47, 47); // Red text
                pdf.setFontSize(8);
                pdf.text(`${objectSewingOffset}mm`, motherX + mother.width + 2, motherY + objectSewingOffset + 1);
                break;
              case 'left':
                // Draw vertical line at offset from left
                pdf.line(motherX + objectSewingOffset, motherY, motherX + objectSewingOffset, motherY + mother.height);
                // Add dimension text
                pdf.setTextColor(211, 47, 47); // Red text
                pdf.setFontSize(8);
                pdf.text(`${objectSewingOffset}mm`, motherX + objectSewingOffset + 2, motherY - 2);
                break;
              case 'right':
                // Draw vertical line at offset from right
                pdf.line(motherX + mother.width - objectSewingOffset, motherY, motherX + mother.width - objectSewingOffset, motherY + mother.height);
                // Add dimension text
                pdf.setTextColor(211, 47, 47); // Red text
                pdf.setFontSize(8);
                pdf.text(`${objectSewingOffset}mm`, motherX + mother.width - objectSewingOffset + 2, motherY - 2);
                break;
              case 'bottom':
                // Draw horizontal line at offset from bottom
                pdf.line(motherX, motherY + mother.height - objectSewingOffset, motherX + mother.width, motherY + mother.height - objectSewingOffset);
                // Add dimension text
                pdf.setTextColor(211, 47, 47); // Red text
                pdf.setFontSize(8);
                pdf.text(`${objectSewingOffset}mm`, motherX + mother.width + 2, motherY + mother.height - objectSewingOffset + 1);
                break;
            }

            // Reset to black for other elements
            pdf.setDrawColor(0, 0, 0);
            pdf.setTextColor(0, 0, 0);
            pdf.setLineDashPattern([], 0); // Reset to solid line
          }
        }

        // Draw mother margin lines (black dotted) if they exist and supporting lines are enabled (and not in only preview mode)
        const motherMargins = (mother as any).margins;
        if (motherMargins && showSupportingLines && !onlyPreview) {
          pdf.setDrawColor(0, 0, 0); // Black for all lines
          pdf.setLineWidth(0.2); // Fine style - very thin lines

          // Top margin line (7mm from top) - offset 0
          if (motherMargins.top > 0) {
            pdf.setLineDashPattern([1, 1], 0); // No offset for horizontal lines
            pdf.line(motherX, motherY + motherMargins.top, motherX + mother.width, motherY + motherMargins.top);
          }
          // Bottom margin line (7mm from bottom) - offset 0.5
          if (motherMargins.bottom > 0) {
            pdf.setLineDashPattern([1, 1], 0.5); // Different offset to prevent overlap
            pdf.line(motherX, motherY + mother.height - motherMargins.bottom, motherX + mother.width, motherY + mother.height - motherMargins.bottom);
          }
          // Left margin line (7mm from left) - offset 0.25
          if (motherMargins.left > 0) {
            pdf.setLineDashPattern([1, 1], 0.25); // Different offset for vertical lines
            pdf.line(motherX + motherMargins.left, motherY, motherX + motherMargins.left, motherY + mother.height);
          }
          // Right margin line (7mm from right) - offset 0.75
          if (motherMargins.right > 0) {
            pdf.setLineDashPattern([1, 1], 0.75); // Different offset to prevent overlap
            pdf.line(motherX + mother.width - motherMargins.right, motherY, motherX + mother.width - motherMargins.right, motherY + mother.height);
          }

          pdf.setLineDashPattern([], 0); // Reset to solid line
        }

        // Draw mid fold lines if they exist and sewing lines are enabled (and not in only preview mode)
        const midFoldLine = (mother as any).midFoldLine;
        if (midFoldLine && midFoldLine.enabled && showSewingLines && !onlyPreview) {
          // Use the properly offset motherX and motherY coordinates
          const padding = midFoldLine.padding || 3;

          if (midFoldLine.type === 'horizontal') {
            // Calculate Y position of mid-fold line
            let midFoldY: number;
            if (midFoldLine.position.useDefault) {
              midFoldY = mother.height / 2;
            } else {
              if (midFoldLine.direction === 'top') {
                midFoldY = midFoldLine.position.customDistance;
              } else { // bottom
                midFoldY = mother.height - midFoldLine.position.customDistance;
              }
            }

            // Draw horizontal fold line (black dotted)
            pdf.setDrawColor(0, 0, 0); // Black for all lines
            pdf.setLineWidth(0.2); // Fine style - very thin lines
            pdf.setLineDashPattern([1, 1], 0.1); // Fine style with unique offset
            pdf.line(motherX, motherY + midFoldY, motherX + mother.width, motherY + midFoldY);

            // Draw fold padding margin lines (dotted, no fill) only if supporting lines are enabled (and not in only preview mode)
            if (showSupportingLines && !onlyPreview) {
              pdf.setDrawColor(0, 0, 0); // Black for all lines
              pdf.setLineWidth(0.2); // Fine style - very thin lines

              // Top padding line - different offset
              pdf.setLineDashPattern([1, 1], 0.3); // Different offset to prevent overlap
              pdf.line(motherX, motherY + midFoldY - padding/2, motherX + mother.width, motherY + midFoldY - padding/2);
              // Bottom padding line - different offset
              pdf.setLineDashPattern([1, 1], 0.7); // Different offset to prevent overlap
              pdf.line(motherX, motherY + midFoldY + padding/2, motherX + mother.width, motherY + midFoldY + padding/2);
            }

            // Add padding dimension labels only if dimensions toggle is enabled
            if (showDimensions) {
              pdf.setFont('helvetica', 'normal'); // Ensure Arial font for labels
              pdf.setFontSize(8); // Standard font size
              pdf.setTextColor(0, 0, 0); // Black text
              pdf.text(`${padding}mm`, motherX + mother.width + 2, motherY + midFoldY);
            }

          } else if (midFoldLine.type === 'vertical') {
            // Calculate X position of mid-fold line
            let midFoldX: number;
            if (midFoldLine.position.useDefault) {
              midFoldX = mother.width / 2;
            } else {
              if (midFoldLine.direction === 'left') {
                midFoldX = midFoldLine.position.customDistance;
              } else { // right
                midFoldX = mother.width - midFoldLine.position.customDistance;
              }
            }

            // Draw vertical fold line (black dotted)
            pdf.setDrawColor(0, 0, 0); // Black for all lines
            pdf.setLineWidth(0.2); // Fine style - very thin lines
            pdf.setLineDashPattern([1, 1], 0.2); // Fine style with unique offset
            pdf.line(motherX + midFoldX, motherY, motherX + midFoldX, motherY + mother.height);

            // Draw fold padding margin lines (dotted, no fill) only if supporting lines are enabled (and not in only preview mode)
            if (showSupportingLines && !onlyPreview) {
              pdf.setDrawColor(0, 0, 0); // Black for all lines
              pdf.setLineWidth(0.2); // Fine style - very thin lines

              // Left padding line - different offset
              pdf.setLineDashPattern([1, 1], 0.4); // Different offset to prevent overlap
              pdf.line(motherX + midFoldX - padding/2, motherY, motherX + midFoldX - padding/2, motherY + mother.height);
              // Right padding line - different offset
              pdf.setLineDashPattern([1, 1], 0.8); // Different offset to prevent overlap
              pdf.line(motherX + midFoldX + padding/2, motherY, motherX + midFoldX + padding/2, motherY + mother.height);
            }

            // Add padding dimension labels only if dimensions toggle is enabled
            if (showDimensions) {
              pdf.setFont('helvetica', 'normal'); // Ensure Arial font for labels
              pdf.setFontSize(8); // Standard font size
              pdf.setTextColor(0, 0, 0); // Black text
              pdf.text(`${padding}mm`, motherX + midFoldX - 5, motherY + mother.height + 8);
            }
          }

          pdf.setLineDashPattern([], 0); // Reset to solid line
        }

        // Add mother margin dimension labels only if dimensions toggle is enabled
        if (motherMargins && showDimensions) {
          pdf.setFont('helvetica', 'normal'); // Ensure Arial font for labels
          pdf.setFontSize(8); // Standard font size
          pdf.setTextColor(0, 0, 0); // Black text

          // Use the properly offset motherX and motherY coordinates
          // Top margin label
          if (motherMargins.top > 0) {
            pdf.text(`${motherMargins.top}mm`, motherX - 15, motherY + motherMargins.top);
          }
          // Bottom margin label
          if (motherMargins.bottom > 0) {
            pdf.text(`${motherMargins.bottom}mm`, motherX - 15, motherY + mother.height - motherMargins.bottom);
          }
          // Left margin label
          if (motherMargins.left > 0) {
            pdf.text(`${motherMargins.left}mm`, motherX + motherMargins.left - 5, motherY - 5);
          }
          // Right margin label
          if (motherMargins.right > 0) {
            pdf.text(`${motherMargins.right}mm`, motherX + mother.width - motherMargins.right - 5, motherY - 5);
          }
        }

        // Draw regions with content and slices
        motherRegions.forEach((region: any, regionIndex: number) => {
          const regionX = motherX + region.x;
          const regionY = motherY + region.y;

          // Check if region has child slices
          const hasSlices = region.children && region.children.length > 0;

          if (hasSlices) {
            // Draw parent region lines only if region borders are enabled (and not in only preview mode)
            if (showRegionBorders && !onlyPreview) {
              // Solid black region borders when region borders are enabled
              pdf.setDrawColor(0, 0, 0); // Black for parent
              pdf.setLineWidth(0.3); // Standard thickness
              pdf.setLineDashPattern([], 0); // Solid line
              pdf.rect(regionX, regionY, region.width, region.height);
            }

            // NOTE: Region margin lines removed to match canvas behavior
            // Canvas doesn't show region margin lines, so PDF shouldn't either

            // Add parent region label - top-left, bold (only if partition names are enabled and not in only preview mode)
            if (showPartitionNames && !onlyPreview) {
              pdf.setFontSize(8);
              pdf.setFont('helvetica', 'bold'); // Bold font for region labels
              pdf.setTextColor(0, 0, 0); // Black text
              pdf.text(`R${regionIndex + 1}`, regionX + 1, regionY + 4);
            }

            // Draw child slices (slices have absolute coordinates within mother, need to make relative to region)
            region.children.forEach((childRegion: any, childIndex: number) => {
              // childRegion.x/y are absolute within mother, region.x/y are also absolute within mother
              // So slice position relative to region is: childRegion.x - region.x
              const relativeX = childRegion.x - region.x;
              const relativeY = childRegion.y - region.y;
              const childX = regionX + relativeX;
              const childY = regionY + relativeY;

              // Draw slice outline only if region borders are enabled (and not in only preview mode)
              if (showRegionBorders && !onlyPreview) {
                pdf.setDrawColor(0, 0, 0); // Black for slices
                pdf.setLineWidth(0.3); // Standard thickness
                pdf.rect(childX, childY, childRegion.width, childRegion.height);
              }

              // Draw slice supporting lines (black dotted) if supporting lines are enabled (and not in only preview mode)
              // Use different offset to prevent overlap with parent region lines
              if (showSupportingLines && !onlyPreview) {
                pdf.setDrawColor(0, 0, 0); // Black for all lines
                pdf.setLineWidth(0.2); // Fine style - very thin lines
                pdf.setLineDashPattern([1, 1], 0.25); // Fine style with different offset
                pdf.rect(childX, childY, childRegion.width, childRegion.height);
                pdf.setLineDashPattern([], 0); // Reset to solid line
              }

              // NOTE: Child region margin lines removed to match canvas behavior
              // Canvas doesn't show region margin lines, so PDF shouldn't either

              // Add slice label - top-right, regular font (only if partition names are enabled and not in only preview mode)
              if (showPartitionNames && !onlyPreview) {
                pdf.setFontSize(8);
                pdf.setFont('helvetica', 'normal'); // Regular font for slice labels
                pdf.setTextColor(0, 0, 0); // Black text
                // Position at top-right corner of slice
                const sliceLabelX = childX + childRegion.width - 1; // Right edge minus small margin
                pdf.text(`S${childIndex + 1}`, sliceLabelX, childY + 4, { align: 'right' });
              }

              // Add content type for slice - intelligent text sizing based on available space
              if (isProjectMode && childRegion.width > 3 && childRegion.height > 2) {
                const sliceContents = regionContents.get(childRegion.id) || [];
                console.log(`🔍 Slice ${childIndex + 1} (${childRegion.id}):`, {
                  width: childRegion.width,
                  height: childRegion.height,
                  hasContent: sliceContents.length > 0,
                  contentCount: sliceContents.length,
                  contents: sliceContents
                });
                if (sliceContents.length > 0) {
                  const content = sliceContents[0]; // Show only first content type

                  // Get actual text content for text-based content types
                  let fullText = content.type; // Default to content type
                  if (content.content && content.content.text) {
                    // For paragraph and line text, show the actual text content
                    fullText = content.content.text;
                  } else if (content.content && content.content.primaryContent) {
                    // For translation paragraphs, show primary content
                    fullText = content.content.primaryContent;
                  }

                  // Abbreviated labels for small spaces (fallback when text is too long)
                  const abbreviatedLabels: { [key: string]: string } = {
                    'line-text': 'text',
                    'pure-english-paragraph': 'eng',
                    'translation-paragraph': 'trans',
                    'washing-symbol': 'wash',
                    'image': 'img',
                    'coo': 'coo'
                  };

                  // Calculate available space for text (more conservative estimate)
                  const availableWidth = childRegion.width - 2; // 1mm margin on each side
                  const charWidth = 0.8; // More conservative character width in mm at 8pt
                  const maxChars = Math.floor(availableWidth / charWidth);

                  console.log(`🔍 Slice ${childIndex + 1} space calc:`, {
                    sliceWidth: childRegion.width,
                    availableWidth,
                    maxChars,
                    fullTextLength: fullText.length,
                    fullText,
                    contentType: content.type
                  });

                  // Choose display text based on available space - use same logic as web view
                  let displayText: string;
                  if (childRegion.width >= 5 && childRegion.height >= 3) {
                    // If slice has minimum dimensions, use full text (will be wrapped exactly like web)
                    displayText = fullText;
                  } else {
                    // Too small for any text (same as web view)
                    displayText = '';
                  }

                  // Only render text if we have something to show
                  if (displayText) {
                    // Get the actual content object to access typography and layout settings
                    const contentObj = sliceContents[0];

                    // Extract typography/layout from the correct config source per content type
                    let cFontSize: number;
                    let cFontFamily: string;
                    let cFontColor: string;
                    let cTextAlign: string;
                    let cVerticalAlign: string;
                    let cPadding: { top: number; right: number; bottom: number; left: number };
                    let cFontSizeUnit: string;

                    if (content.type === 'new-comp-trans' && content.newCompTransConfig) {
                      const cfg = content.newCompTransConfig;
                      cFontSize = cfg.typography?.fontSize || 12;
                      cFontFamily = cfg.typography?.fontFamily || 'helvetica';
                      cFontSizeUnit = cfg.typography?.fontSizeUnit || 'px';
                      cFontColor = cfg.typography?.fontColor || '#000000';
                      cTextAlign = cfg.alignment?.horizontal || 'left';
                      cVerticalAlign = cfg.alignment?.vertical || 'top';
                      cPadding = cfg.padding || { top: 2, right: 2, bottom: 2, left: 2 };
                    } else if (content.type === 'new-multi-line' && content.newMultiLineConfig) {
                      const cfg = content.newMultiLineConfig;
                      cFontSize = cfg.typography?.fontSize || 12;
                      cFontFamily = cfg.typography?.fontFamily || 'helvetica';
                      cFontSizeUnit = cfg.typography?.fontSizeUnit || 'px';
                      cFontColor = cfg.typography?.fontColor || '#000000';
                      cTextAlign = cfg.alignment?.horizontal || 'left';
                      cVerticalAlign = cfg.alignment?.vertical || 'top';
                      cPadding = cfg.padding || { top: 2, right: 2, bottom: 2, left: 2 };
                    } else if (content.type === 'new-line-text' && content.newLineTextConfig) {
                      const cfg = content.newLineTextConfig;
                      cFontSize = cfg.typography?.fontSize || 12;
                      cFontFamily = cfg.typography?.fontFamily || 'helvetica';
                      cFontSizeUnit = cfg.typography?.fontSizeUnit || 'px';
                      cFontColor = cfg.typography?.fontColor || '#000000';
                      cTextAlign = cfg.alignment?.horizontal || 'left';
                      cVerticalAlign = cfg.alignment?.vertical || 'top';
                      cPadding = cfg.padding || { top: 2, right: 2, bottom: 2, left: 2 };
                    } else if (content.type === 'new-washing-care-symbol' && content.newWashingCareSymbolConfig) {
                      const cfg = content.newWashingCareSymbolConfig;
                      cFontSize = cfg.typography?.fontSize || 12;
                      cFontFamily = cfg.typography?.fontFamily || 'helvetica';
                      cFontSizeUnit = cfg.typography?.fontSizeUnit || 'px';
                      cFontColor = cfg.typography?.fontColor || '#000000';
                      cTextAlign = cfg.alignment?.horizontal || 'left';
                      cVerticalAlign = cfg.alignment?.vertical || 'top';
                      cPadding = cfg.padding || { top: 2, right: 2, bottom: 2, left: 2 };
                    } else {
                      const effTyp = contentObj.typography || {};
                      const effLay = contentObj.layout || {};
                      cFontSize = effTyp.fontSize || 12;
                      cFontFamily = effTyp.fontFamily || 'helvetica';
                      cFontSizeUnit = 'px';
                      cFontColor = effTyp.fontColor || '#000000';
                      cTextAlign = effLay.horizontalAlign || 'left';
                      cVerticalAlign = effLay.verticalAlign || 'top';
                      cPadding = effLay.padding || { top: 2, right: 2, bottom: 2, left: 2 };
                    }

                    let cFontSizeInPx = cFontSize;
                    if (cFontSizeUnit === 'pt') cFontSizeInPx = cFontSize * 4/3;
                    else if (cFontSizeUnit === 'mm') cFontSizeInPx = cFontSize * 3.779527559;

                    // EXACT WEB REPLICATION: Match web view pixel-perfect
                    const scaledFontSize = Math.max(6, cFontSizeInPx);
                    const webLineHeightPx = scaledFontSize * 1.2;

                    // Convert web pixels to PDF units (1px = 0.264583mm at 96 DPI)
                    const pdfFontSize = scaledFontSize * 0.75;
                    const lineHeightMM = webLineHeightPx * 0.264583;

                    // Copy into local vars used by rest of the block
                    const fontSize = cFontSize;
                    const fontFamily = cFontFamily;
                    const fontColor = cFontColor;
                    const textAlign = cTextAlign;
                    const verticalAlign = cVerticalAlign;
                    const padding = cPadding;

                    pdf.setFontSize(pdfFontSize);
                    pdf.setFont(fontFamily === 'Arial' ? 'helvetica' : fontFamily, 'normal');

                    // Convert hex color to RGB exactly like web
                    const hexToRgb = (hex: string) => {
                      const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
                      return result ? {
                        r: parseInt(result[1], 16),
                        g: parseInt(result[2], 16),
                        b: parseInt(result[3], 16)
                      } : { r: 0, g: 0, b: 0 };
                    };
                    const color = hexToRgb(fontColor);
                    pdf.setTextColor(color.r, color.g, color.b);

                    // Calculate text area with exact padding like web view
                    const paddingTop = padding.top || 0;
                    const paddingRight = padding.right || 0;
                    const paddingBottom = padding.bottom || 0;
                    const paddingLeft = padding.left || 0;

                    const textAreaWidth = Math.max(0, childRegion.width - paddingLeft - paddingRight);
                    const textAreaHeight = Math.max(0, childRegion.height - paddingTop - paddingBottom);

                    // Use pre-wrapped lines from N-split (already wrapped by canvas measureText)
                    // Do NOT re-wrap with jsPDF's splitTextToSize - it uses different font metrics
                    const wrappedText = displayText.split('\n');

                    // Calculate max lines exactly like web view (with baseline offset)
                    // Web view: maxLines = floor((height - fontSize*0.8) / lineHeight)
                    const fontSizeMM = pdfFontSize * 0.264583; // pt to mm (1pt = 0.264583mm)
                    const baselineOffsetMM = fontSizeMM * 0.8;
                    const safeTextAreaHeight = Math.max(0, textAreaHeight - baselineOffsetMM);
                    const maxLines = Math.max(0, Math.floor(safeTextAreaHeight / lineHeightMM));

                    if (maxLines > 0) {
                      let displayLines = wrappedText;
                      if (displayLines.length > maxLines) {
                        displayLines = wrappedText.slice(0, maxLines);
                      }

                      // Calculate horizontal alignment exactly like web view
                      let textX = childX + paddingLeft;
                      if (textAlign === 'center') {
                        textX = childX + childRegion.width / 2;
                      } else if (textAlign === 'right') {
                        textX = childX + childRegion.width - paddingRight;
                      }

                      // Calculate vertical alignment exactly like web view
                      // Web: startY = baseY + (region.y * scale) + paddingTopPx;
                      let startY = childY + paddingTop;
                      if (verticalAlign === 'center') {
                        // Web: totalTextHeight = displayLines.length * lineHeight;
                        const totalTextHeight = displayLines.length * lineHeightMM;
                        // Web: startY = baseY + (region.y * scale) + (regionHeightPx - totalTextHeight) / 2;
                        startY = childY + (childRegion.height - totalTextHeight) / 2;
                      } else if (verticalAlign === 'bottom') {
                        const totalTextHeight = displayLines.length * lineHeightMM;
                        // Web: startY = baseY + (region.y * scale) + regionHeightPx - paddingBottomPx - totalTextHeight;
                        startY = childY + childRegion.height - paddingBottom - totalTextHeight;
                      }

                      // Handle washing care symbols, graphics, or regular text in child regions
                      if (content.type === 'new-graphic' && content.content?.pdfData) {
                        // Render PDF graphic content in PDF export (child region)
                        console.log('🎨 Rendering graphic content to PDF (child):', content.content.pdfFileName);

                        const effectiveLayout = content.layout || {};
                        const padding = effectiveLayout.padding || { top: 0, right: 0, bottom: 0, left: 0 };

                        // Calculate available space after padding
                        const availableWidth = Math.max(0, childRegion.width - padding.left - padding.right);
                        const availableHeight = Math.max(0, childRegion.height - padding.top - padding.bottom);

                        // Calculate position with padding
                        const graphicX = childX + padding.left;
                        const graphicY = childY + padding.top;

                        try {
                          // Add the rendered PDF image to the PDF export
                          pdf.addImage(
                            content.content.pdfData,
                            'PNG',
                            graphicX,
                            graphicY,
                            availableWidth,
                            availableHeight,
                            undefined,
                            'FAST'
                          );
                          console.log('✅ Graphic content added to PDF (child):', {
                            x: graphicX,
                            y: graphicY,
                            width: availableWidth,
                            height: availableHeight
                          });
                        } catch (error) {
                          console.error('❌ Error adding graphic to PDF (child):', error);
                        }
                      } else if (content.type === 'new-washing-care-symbol') {
                        // Render washing care symbols in PDF for child regions using configuration
                        const symbols = content.content?.symbols || ['b', 'G', '5', 'B', 'J'];

                        // Use configuration settings if available
                        const configIconSize = content.content?.iconSize || 8; // Default 8mm
                        const configPadding = content.content?.padding || { top: 2, left: 2, bottom: 2, right: 2 };
                        const configAlignment = content.content?.alignment || { horizontal: 'center', vertical: 'center' };

                        // Calculate available space after padding
                        const availableWidth = childRegion.width - configPadding.left - configPadding.right;
                        const availableHeight = childRegion.height - configPadding.top - configPadding.bottom;
                        const symbolSpacing = availableWidth / symbols.length;

                        // Calculate container position based on alignment
                        let containerX = childX + configPadding.left;
                        let containerY = childY + configPadding.top;

                        if (configAlignment.horizontal === 'center') {
                          containerX = childX + (childRegion.width / 2) - (availableWidth / 2);
                        } else if (configAlignment.horizontal === 'right') {
                          containerX = childX + childRegion.width - configPadding.right - availableWidth;
                        }

                        if (configAlignment.vertical === 'center') {
                          containerY = childY + (childRegion.height / 2) - (configIconSize / 2);
                        } else if (configAlignment.vertical === 'bottom') {
                          containerY = childY + childRegion.height - configPadding.bottom - configIconSize;
                        }

                        // For PDF, use the same font as canvas - embed Wash Care Symbols M54 font (child regions)
                        symbols.forEach((symbol: string, symbolIndex: number) => {
                          const symbolX = containerX + symbolIndex * symbolSpacing + symbolSpacing / 2;
                          const symbolY = containerY + (configIconSize / 2);

                          // Use canvas rendering first for cross-computer compatibility (child regions)
                          let fontUsed = false;
                          let canvasUsed = false;

                          // Force canvas rendering for better compatibility across computers
                          // Match SVG font size: configIconSize * 3.78px (1mm = 3.78px at 96 DPI)
                          const svgFontSizePx = configIconSize * 3.78; // Match SVG rendering exactly
                          const canvasImage = renderSymbolToCanvas(symbol, svgFontSizePx);
                          if (canvasImage) {
                            try {
                              // Calculate image size in mm to match SVG display exactly
                              // Canvas has padding of 0.2 * size on each side, so total canvas = size * 1.4
                              // To make the font-size pixels map to configIconSize mm, we need:
                              // Canvas total size in PDF = configIconSize * 1.4
                              const imageSize = configIconSize * 1.4; // Account for canvas padding (0.2 * size * 2)
                              const imageX = symbolX - imageSize / 2;
                              const imageY = symbolY - imageSize / 2;

                              // Add the canvas-rendered symbol as image
                              pdf.addImage(canvasImage, 'PNG', imageX, imageY, imageSize, imageSize);
                              canvasUsed = true;
                              console.log(`✅ Used canvas rendering for child symbol: ${symbol} at ${imageSize}mm (1:1 SVG match)`);
                            } catch (error) {
                              console.error('❌ Canvas image failed for child:', error);
                              canvasUsed = false;
                            }
                          }

                          // Fallback to embedded font if canvas fails
                          if (!canvasUsed) {
                            try {
                              // Try to use the embedded Wash Care Symbols M54 font with configured size
                              try {
                                pdf.setFont('Wash Care Symbols M54', 'normal');
                              } catch {
                                pdf.setFont('WashCareSymbolsM54', 'normal');
                              }
                              pdf.setFontSize(configIconSize * 2.83); // Convert mm to points
                              pdf.setTextColor(0, 0, 0);
                              pdf.text(symbol, symbolX, symbolY, { align: 'center', baseline: 'middle' });
                              fontUsed = true;
                              console.log(`✅ Used embedded font for child symbol: ${symbol}`);
                              // Reset font back to Arial/Helvetica for subsequent text rendering
                              pdf.setFont('helvetica', 'normal');
                            } catch (error) {
                              // Font not available
                              console.log(`⚠️ Font not available for child symbol: ${symbol}, error:`, error);
                              fontUsed = false;
                            }
                          }

                          if (!fontUsed) {
                            // Try canvas rendering to capture the actual font symbols
                            // Match SVG font size: configIconSize * 3.78px (1mm = 3.78px at 96 DPI)
                            const svgFontSizePx = configIconSize * 3.78; // Match SVG rendering exactly
                            const canvasImage = renderSymbolToCanvas(symbol, svgFontSizePx);
                            if (canvasImage) {
                              try {
                                // Calculate image size in mm to match SVG display exactly
                                // Canvas total size in PDF = configIconSize * 1.4 (includes padding)
                                const imageSize = configIconSize * 1.4; // Account for canvas padding (0.2 * size * 2)
                                const imageX = symbolX - imageSize / 2;
                                const imageY = symbolY - imageSize / 2;

                                // Add the canvas-rendered symbol as image
                                pdf.addImage(canvasImage, 'PNG', imageX, imageY, imageSize, imageSize);
                                canvasUsed = true;
                                // console.log('✅ Used canvas rendering for child symbol:', symbol);
                              } catch (error) {
                                console.error('❌ Canvas image failed for child:', error);
                                canvasUsed = false;
                              }
                            }
                          }

                          if (!fontUsed && !canvasUsed) {
                            // Fallback: Create vector shapes that match the canvas symbols exactly (child regions)
                            pdf.setDrawColor(0, 0, 0);
                            pdf.setFillColor(255, 255, 255);
                            pdf.setLineWidth(0.3);

                          // Create shapes that exactly match the Wash Care Symbols M54 font appearance (smaller for child regions)
                          switch (symbolIndex) {
                            case 0: // Washing (b) - Basin shape exactly like canvas font
                              // Draw basin with curved bottom like the font symbol
                              const basinWidth = configIconSize * 0.6;
                              const basinHeight = configIconSize * 0.4;
                              // Top rim
                              pdf.line(symbolX - basinWidth/2, symbolY - basinHeight/2, symbolX + basinWidth/2, symbolY - basinHeight/2);
                              // Left side
                              pdf.line(symbolX - basinWidth/2, symbolY - basinHeight/2, symbolX - basinWidth/3, symbolY + basinHeight/2);
                              // Right side
                              pdf.line(symbolX + basinWidth/2, symbolY - basinHeight/2, symbolX + basinWidth/3, symbolY + basinHeight/2);
                              // Bottom curve (approximated with line)
                              pdf.line(symbolX - basinWidth/3, symbolY + basinHeight/2, symbolX + basinWidth/3, symbolY + basinHeight/2);
                              break;
                            case 1: // Drying (G) - Square exactly like canvas font
                              const squareSize = configIconSize * 0.5;
                              pdf.rect(symbolX - squareSize/2, symbolY - squareSize/2, squareSize, squareSize, 'S');
                              break;
                            case 2: // Ironing (5) - Iron shape exactly like canvas font
                              const ironWidth = configIconSize * 0.5;
                              const ironHeight = configIconSize * 0.4;
                              // Iron base (rounded rectangle approximation)
                              pdf.ellipse(symbolX, symbolY + ironHeight/4, ironWidth/2, ironHeight/4, 'S');
                              // Iron point
                              pdf.lines([
                                [0, -ironHeight/2],
                                [ironWidth/4, -ironHeight/4],
                                [ironWidth/4, ironHeight/4],
                                [-ironWidth/4, ironHeight/4],
                                [-ironWidth/4, -ironHeight/4],
                                [0, -ironHeight/2]
                              ], symbolX, symbolY, [1, 1], 'S');
                              break;
                            case 3: // Bleaching (B) - Triangle exactly like canvas font
                              const triSize = configIconSize * 0.4;
                              pdf.triangle(symbolX, symbolY - triSize/2, symbolX + triSize/2, symbolY + triSize/2, symbolX - triSize/2, symbolY + triSize/2, 'S');
                              break;
                            case 4: // Professional (J) - Circle exactly like canvas font
                              const circleRadius = configIconSize * 0.25;
                              pdf.circle(symbolX, symbolY, circleRadius, 'S');
                              break;
                          }
                          } // End of fallback vector shapes (child regions)
                        });
                      } else if (content.type === 'new-comp-trans' || content.type === 'new-multi-line') {
                        // Render composition translation / multi-line text in PDF for child regions using configuration
                        const config = content.type === 'new-comp-trans' ? content.newCompTransConfig : content.newMultiLineConfig;
                        if (!config || !config.padding || !config.alignment || !config.typography) {
                          console.warn(`🌐 child ${content.type} missing configuration, skipping PDF render`);
                          return;
                        }

                        const configPadding = config.padding;
                        const configAlignment = config.alignment;
                        const configTypography = config.typography;

                        console.log(`🔍 PDF ${content.type} alignment:`, {
                          horizontal: configAlignment.horizontal,
                          vertical: configAlignment.vertical,
                          contentType: content.type
                        });

                        // Calculate available space after padding
                        const availableWidth = childRegion.width - configPadding.left - configPadding.right;
                        const availableHeight = childRegion.height - configPadding.top - configPadding.bottom;

                        // Calculate text position based on alignment
                        let textX = childX + configPadding.left;
                        let textY = childY + configPadding.top;

                        if (configAlignment.horizontal === 'center') {
                          textX = childX + (childRegion.width / 2);
                        } else if (configAlignment.horizontal === 'right') {
                          textX = childX + childRegion.width - configPadding.right;
                        }

                        if (configAlignment.vertical === 'center') {
                          textY = childY + (childRegion.height / 2);
                        } else if (configAlignment.vertical === 'bottom') {
                          textY = childY + childRegion.height - configPadding.bottom;
                        }

                        // Set font and render text with proper wrapping
                        pdf.setFont('helvetica', 'normal');

                        let fontSize = configTypography.fontSize;
                        if (configTypography.fontSizeUnit === 'pt') {
                          fontSize = fontSize * 0.352778; // Convert pt to mm
                        } else if (configTypography.fontSizeUnit === 'px') {
                          fontSize = fontSize * 0.264583; // Convert px to mm
                        }
                        pdf.setFontSize(fontSize * 2.83); // Convert mm to points for jsPDF
                        pdf.setTextColor(0, 0, 0);

                        const textContent = content.type === 'new-comp-trans'
                          ? (content.newCompTransConfig?.textContent?.generatedText || 'Composition Translation')
                          : (content.content?.text || 'Multiple Line');

                        // Use EXACT same text wrapping logic as canvas rendering
                        // Match canvas calculation: availableWidthPx = Math.max(0, regionWidthPx - paddingLeftPx - paddingRightPx)
                        const availableWidthPx = Math.max(0, availableWidth * 3.779527559); // Convert mm to px
                        const availableHeightPx = Math.max(0, availableHeight * 3.779527559);

                        // Match canvas font size calculation (no zoom factor in PDF)
                        let fontSizeForProcessing = configTypography.fontSize;
                        if (configTypography.fontSizeUnit === 'pt') {
                          fontSizeForProcessing = configTypography.fontSize * 4/3; // Convert points to pixels
                        } else if (configTypography.fontSizeUnit === 'mm') {
                          fontSizeForProcessing = configTypography.fontSize * 3.779527559; // Convert mm to pixels
                        }
                        const scaledFontSize = Math.max(6, fontSizeForProcessing); // No zoom in PDF, but keep minimum

                        // 🎯 SELECTIVE CTP METHOD: Use different rendering based on mother type
                        // Mother 1 & 2: Use old method (text-based, copyable)
                        // Mother 3+: Use CTP method (image-based) for composition translation content
                        // Exception: Always use CTP method for new-comp-trans and new-multi-line to preserve exact font sizing
                        const motherName = mother.name || '';
                        const motherNumber = parseInt(motherName.match(/Mother_(\d+)/)?.[1] || '1');
                        const forceCanvasToImageMethod = motherNumber >= 3 || content.type === 'new-comp-trans' || content.type === 'new-multi-line'; // Force CTP for new-comp-trans and new-multi-line

                        if (forceCanvasToImageMethod) {
                          console.log(`🎯 Using CTP method for ${motherName} (Mother ${motherNumber}) - composition translation as image`);

                          // SOLUTION: Capture the exact canvas region that's displayed to the user
                          // Find the actual SVG text element that's rendered on screen
                          const svgElement = document.querySelector('svg');
                          if (svgElement) {
                            try {
                              // Create a temporary canvas to capture the exact SVG region
                              const tempCanvas = document.createElement('canvas');
                              const tempCtx = tempCanvas.getContext('2d');

                              if (tempCtx) {
                                // Set canvas size to match the region exactly
                                const dpiScale = 2; // Higher DPI for quality
                                tempCanvas.width = availableWidthPx * dpiScale;
                                tempCanvas.height = availableHeightPx * dpiScale;
                                tempCtx.scale(dpiScale, dpiScale);

                                // Fill with white background
                                tempCtx.fillStyle = '#FFFFFF';
                                tempCtx.fillRect(0, 0, availableWidthPx, availableHeightPx);

                                // Set font and style to EXACTLY match the SVG rendering
                                tempCtx.font = `${scaledFontSize}px ${configTypography.fontFamily}`;
                                tempCtx.fillStyle = configTypography.color || '#000000';
                                tempCtx.textAlign = configAlignment.horizontal === 'center' ? 'center' :
                                                  configAlignment.horizontal === 'right' ? 'right' : 'left';
                                tempCtx.textBaseline = 'top';

                                // Use the EXACT same text wrapping as displayed on screen
                                const wrappedResult = processChildRegionTextWrapping(
                                  textContent,
                                  availableWidthPx,
                                  availableHeightPx,
                                  scaledFontSize,
                                  configTypography.fontFamily,
                                  config.lineBreakSettings?.lineBreakSymbol || config.lineBreak?.symbol || '\n',
                                  config.lineBreakSettings?.lineSpacing || config.lineBreak?.lineSpacing || 1.2
                                );

                                // Render each line with EXACT positioning including vertical alignment
                                const lineHeightPx = scaledFontSize * (config.lineBreakSettings?.lineSpacing || config.lineBreak?.lineSpacing || 1.2);
                                const totalTextHeight = wrappedResult.lines.length * lineHeightPx;

                                // Calculate vertical starting position based on alignment
                                let startY = 0; // Default: top
                                if (configAlignment.vertical === 'center') {
                                  startY = (availableHeightPx - totalTextHeight) / 2;
                                } else if (configAlignment.vertical === 'bottom') {
                                  startY = availableHeightPx - totalTextHeight;
                                }

                                wrappedResult.lines.forEach((line: string, lineIndex: number) => {
                                  const lineY = startY + (lineIndex * lineHeightPx);
                                  let lineX = 0;
                                  if (configAlignment.horizontal === 'center') {
                                    // Use logical canvas width (before dpiScale), same as working implementation
                                    lineX = availableWidthPx / 2;
                                  } else if (configAlignment.horizontal === 'right') {
                                    lineX = availableWidthPx;
                                  }
                                  tempCtx.fillText(line, lineX, lineY);
                                });

                                // Convert to high-quality image and add to PDF
                                const imgData = tempCanvas.toDataURL('image/png', 1.0);
                                const imgWidthMM = availableWidth;
                                const imgHeightMM = availableHeight;

                                // Place canvas at content area start point (use correct coordinate system like line 10617)
                                const relativeX = childRegion.x - region.x;
                                const relativeY = childRegion.y - region.y;
                                const childX = regionX + relativeX;
                                const childY = regionY + relativeY;
                                const contentStartX = childX + configPadding.left;
                                const contentStartY = childY + configPadding.top;
                                pdf.addImage(imgData, 'PNG', contentStartX, contentStartY, imgWidthMM, imgHeightMM, undefined, 'FAST');

                                // console.log('📋 Exact canvas-to-PDF rendering complete (pixel-perfect match)');

                                // Create selectable text overlay for webpage interaction
                                const regionBounds = {
                                  x: textX * (96 / 25.4), // Convert mm to pixels (96 DPI)
                                  y: textY * (96 / 25.4),
                                  width: availableWidth * (96 / 25.4),
                                  height: availableHeight * (96 / 25.4),
                                  fontSize: fontSize * (96 / 25.4) / 2.83, // Convert back to screen pixels
                                  fontFamily: configTypography.fontFamily
                                };
                                createSelectableTextOverlay(`child-${childRegion.id}`, textContent, regionBounds);
                                return;
                              }
                            } catch (error) {
                              console.warn('Canvas capture failed, falling back to regular text rendering:', error);
                            }
                          }

                          // Fallback to regular text rendering if canvas capture fails
                          const wrappedResult = processChildRegionTextWrapping(
                            textContent,
                            availableWidthPx,
                            availableHeightPx,
                            scaledFontSize,
                            configTypography.fontFamily,
                            config.lineBreakSettings?.lineBreakSymbol || config.lineBreak?.symbol || '\n',
                            config.lineBreakSettings?.lineSpacing || config.lineBreak?.lineSpacing || 1.2
                          );

                          const lineHeightMM = fontSize * (config.lineBreakSettings?.lineSpacing || config.lineBreak?.lineSpacing || 1.2);
                          const alignOption = configAlignment.horizontal === 'center' ? 'center' :
                                             configAlignment.horizontal === 'right' ? 'right' : 'left';

                          wrappedResult.lines.forEach((line: string, lineIndex: number) => {
                            const lineY = textY + (lineIndex * lineHeightMM);
                            pdf.text(line.trim(), textX, lineY, { align: alignOption });
                          });

                        } else {
                          // Use normal text rendering for Mother 1 & 2 (copyable text)
                          console.log(`📝 Using text method for ${motherName} (Mother ${motherNumber}) - copyable text`);
                          const wrappedResult = processChildRegionTextWrapping(
                            textContent,
                            availableWidthPx,
                            availableHeightPx,
                            scaledFontSize,
                            configTypography.fontFamily,
                            config.lineBreakSettings?.lineBreakSymbol || config.lineBreak?.symbol || '\n',
                            config.lineBreakSettings?.lineSpacing || config.lineBreak?.lineSpacing || 1.2
                          );

                          const lineHeightMM = fontSize * (config.lineBreakSettings?.lineSpacing || config.lineBreak?.lineSpacing || 1.2);
                          const alignOption = configAlignment.horizontal === 'center' ? 'center' :
                                             configAlignment.horizontal === 'right' ? 'right' : 'left';

                          // console.log('🖨️ PDF Composition Text Rendering (Child) - DETAILED DEBUG:', {
                          //   originalText: textContent,
                          //   availableWidthMm: availableWidth,
                          //   availableHeightMm: availableHeight,
                          //   availableWidthPx: availableWidthPx,
                          //   availableHeightPx: availableHeightPx,
                          //   fontSizeForProcessing: fontSizeForProcessing,
                          //   scaledFontSize: scaledFontSize,
                          //   fontSizeUnit: configTypography.fontSizeUnit,
                          //   wrappedLines: wrappedResult.lines,
                          //   lineCount: wrappedResult.lines.length,
                          //   hasOverflow: wrappedResult.hasOverflow,
                          //   padding: configPadding
                          // });

                          wrappedResult.lines.forEach((line: string, lineIndex: number) => {
                            const lineY = textY + (lineIndex * lineHeightMM);
                            pdf.text(line.trim(), textX, lineY, { align: alignOption });
                          });
                        }
                      } else {
                        // 🎯 SELECTIVE RENDERING: Use different methods based on mother type
                        const motherName = mother.name || '';
                        const motherNumber = parseInt(motherName.match(/Mother_(\d+)/)?.[1] || '1');
                        const useCanvasMethod = motherNumber >= 3; // Canvas method only for Mother 3+

                        if (useCanvasMethod) {
                          console.log(`🎯 Using canvas method for ${motherName} (Mother ${motherNumber}) - child region as image`);

                        // Create simple canvas
                        const canvas = document.createElement('canvas');
                        const ctx = canvas.getContext('2d');

                        if (ctx) {
                          // Simple canvas size
                          const width = (childRegion.width - paddingLeft - paddingRight) * 4;
                          const height = (childRegion.height - paddingTop - paddingBottom) * 4;
                          canvas.width = width;
                          canvas.height = height;

                          // White background
                          ctx.fillStyle = 'white';
                          ctx.fillRect(0, 0, width, height);

                          // Simple font setup
                          ctx.font = `${fontSize * 4}px ${fontFamily}`;
                          ctx.fillStyle = 'black';
                          ctx.textAlign = textAlign === 'center' ? 'center' : textAlign === 'right' ? 'right' : 'left';

                          // Draw text lines - canvas represents content area, so positioning is simpler
                          displayLines.forEach((line: string, i: number) => {
                            const y = (i + 1) * lineHeightMM * 4;
                            let x = 0;
                            if (textAlign === 'center') x = width / 2;
                            else if (textAlign === 'right') x = width;
                            ctx.fillText(line, x, y);
                          });

                          // Place canvas at content area start point (not textX which is center-aligned)
                          const imgData = canvas.toDataURL('image/png');
                          const contentStartX = regionX + childRegion.x + paddingLeft;
                          const contentStartY = regionY + childRegion.y + paddingTop;
                          pdf.addImage(imgData, 'PNG', contentStartX, contentStartY,
                            childRegion.width - paddingLeft - paddingRight,
                            childRegion.height - paddingTop - paddingBottom);
                        } else {
                          // Simple fallback for canvas method
                          displayLines.forEach((line: string, lineIndex: number) => {
                            const textY = startY + (lineIndex + 1) * lineHeightMM;
                            const align = textAlign === 'center' ? 'center' : textAlign === 'right' ? 'right' : 'left';
                            pdf.text(line, textX, textY, { align: align });
                          });
                        }
                      } else {
                        // Use normal text rendering for Mother 1 & 2 (copyable text)
                          console.log(`📝 Using text method for ${motherName} (Mother ${motherNumber}) - child region copyable text`);

                          displayLines.forEach((line: string, lineIndex: number) => {
                            const textY = startY + (lineIndex + 1) * lineHeightMM;
                            const align = textAlign === 'center' ? 'center' : textAlign === 'right' ? 'right' : 'left';
                            pdf.text(line, textX, textY, { align: align });
                          });
                        }
                      }

                      // Draw content padding boundaries (green dotted lines) for child regions if supporting lines are enabled
                      if (showSupportingLines && !onlyPreview && (paddingTop > 0 || paddingRight > 0 || paddingBottom > 0 || paddingLeft > 0)) {
                        pdf.setDrawColor(76, 175, 80); // Green color (#4CAF50)
                        pdf.setLineWidth(0.2); // Fine style - very thin lines

                        // Top padding line
                        if (paddingTop > 0) {
                          pdf.setLineDashPattern([1, 1], 0.15); // Fine dotted with offset
                          pdf.line(childX + paddingLeft, childY + paddingTop, childX + childRegion.width - paddingRight, childY + paddingTop);
                        }
                        // Bottom padding line - FORCE DRAW if any other padding exists
                        if (paddingBottom > 0 || (paddingTop > 0 || paddingLeft > 0 || paddingRight > 0)) {
                          pdf.setLineDashPattern([1, 1], 0.35); // Different offset to prevent overlap
                          const bottomY = childY + childRegion.height - (paddingBottom > 0 ? paddingBottom : 3); // Use 3mm default if paddingBottom is 0
                          pdf.line(childX + paddingLeft, bottomY, childX + childRegion.width - paddingRight, bottomY);
                          console.log('✅ Drew CHILD BOTTOM padding line at Y:', bottomY, 'paddingBottom:', paddingBottom);
                        }
                        // Left padding line
                        if (paddingLeft > 0) {
                          pdf.setLineDashPattern([1, 1], 0.55); // Different offset for vertical lines
                          pdf.line(childX + paddingLeft, childY + paddingTop, childX + paddingLeft, childY + childRegion.height - paddingBottom);
                        }
                        // Right padding line
                        if (paddingRight > 0) {
                          pdf.setLineDashPattern([1, 1], 0.75); // Different offset to prevent overlap
                          pdf.line(childX + childRegion.width - paddingRight, childY + paddingTop, childX + childRegion.width - paddingRight, childY + childRegion.height - paddingBottom);
                        }

                        pdf.setLineDashPattern([], 0); // Reset to solid line
                      }
                    }
                  }
                }
              }
            });
          } else {
            // Draw regular region lines only if region borders are enabled (and not in only preview mode)
            if (showRegionBorders && !onlyPreview) {
              // Solid black region borders when region borders are enabled
              pdf.setDrawColor(0, 0, 0); // Black for regions
              pdf.setLineWidth(0.3); // Standard thickness
              pdf.setLineDashPattern([], 0); // Solid line
              pdf.rect(regionX, regionY, region.width, region.height);
            }

            // NOTE: Regular region margin lines removed to match canvas behavior
            // Canvas doesn't show region margin lines, so PDF shouldn't either

            // Add region label - top-left, bold (only if partition names are enabled and not in only preview mode)
            if (showPartitionNames && !onlyPreview) {
              pdf.setFontSize(8);
              pdf.setFont('helvetica', 'bold'); // Bold font for region labels
              pdf.setTextColor(0, 0, 0); // Black text
              pdf.text(`R${regionIndex + 1}`, regionX + 1, regionY + 4);
            }

            // Add content type for region - use full text like slices
            logExport(`🔍 REGION CHECK R${regionIndex + 1}:`, {
              isProjectMode,
              width: region.width,
              height: region.height,
              sizeOK: region.width > 10 && region.height > 5,
              willProcess: isProjectMode && region.width > 10 && region.height > 5
            });
            if (isProjectMode && region.width > 10 && region.height > 5) {
              const regionContentsForRegion = regionContents.get(region.id) || [];
              logExport(`🔍 Region R${regionIndex + 1} (${region.id}):`, {
                width: region.width,
                height: region.height,
                hasContent: regionContentsForRegion.length > 0,
                contentCount: regionContentsForRegion.length,
                contents: regionContentsForRegion
              });
              if (regionContentsForRegion.length > 0) {
                // Find content with actual text instead of just taking first item
                let content = regionContentsForRegion[0]; // Default to first

                // Look for content with non-empty text
                for (const item of regionContentsForRegion) {
                  let hasText = false;
                  if (item.content?.text || item.content?.primaryContent) {
                    hasText = true;
                  } else if (item.newCompTransConfig?.textContent?.generatedText) {
                    hasText = item.newCompTransConfig.textContent.generatedText.trim().length > 0;
                  }

                  if (hasText) {
                    content = item;
                    break; // Use first content with actual text
                  }
                }

                logExport(`🎯 CONTENT SELECTION:`, {
                  totalItems: regionContentsForRegion.length,
                  selectedContentId: content.id,
                  selectedContentType: content.type,
                  hasText: !!(content.newCompTransConfig?.textContent?.generatedText?.trim())
                });

                // ENHANCED DEBUG: Log content structure for troubleshooting
                logExport(`🔍 MAIN REGION CONTENT DEBUG (${region.id}):`, {
                  contentType: content.type,
                  hasContent: !!content.content,
                  hasNewCompTransConfig: !!content.newCompTransConfig,
                  fullContentStructure: JSON.stringify(content, null, 2)
                });

                // Get actual text content for text-based content types
                let fullText = content.type; // Default to content type
                if (content.content && content.content.text) {
                  // For paragraph and line text, show the actual text content
                  fullText = content.content.text;
                } else if (content.content && content.content.primaryContent) {
                  // For translation paragraphs, show primary content
                  fullText = content.content.primaryContent;
                } else if (content.newCompTransConfig && content.newCompTransConfig.textContent) {
                  // For new-comp-trans, get text from the config
                  fullText = content.newCompTransConfig.textContent.generatedText || content.type;
                }

                logExport(`🔍 MAIN REGION TEXT EXTRACTION:`, {
                  regionId: region.id,
                  contentType: content.type,
                  extractedText: fullText?.substring(0, 100) + '...',
                  textLength: fullText?.length || 0
                });

                // Calculate available space for text
                const availableWidth = region.width - 4; // 2mm margin on each side
                const charWidth = 0.8; // Character width in mm at 8pt
                const maxChars = Math.floor(availableWidth / charWidth);

                // Choose display text based on available space - use same logic as web view
                let displayText: string;
                if (region.width >= 8 && region.height >= 5) {
                  // If region has minimum dimensions, use full text (will be wrapped exactly like web)
                  displayText = fullText;
                } else {
                  // Too small for any text (same as web view)
                  displayText = '';
                }

                // Get the actual content object to access typography and layout settings
                const contentObj = regionContentsForRegion[0];

                // Use the same typography and layout logic as web view
                let fontSize: number;
                let fontFamily: string;
                let fontColor: string;
                let textAlign: string;
                let verticalAlign: string;
                let padding: { top: number; right: number; bottom: number; left: number };
                let fontSizeUnit: string;

                if (content.type === 'new-comp-trans' && content.newCompTransConfig) {
                  const config = content.newCompTransConfig;
                  fontSize = config.typography?.fontSize || 12;
                  fontFamily = config.typography?.fontFamily || 'helvetica';
                  fontSizeUnit = config.typography?.fontSizeUnit || 'px';
                  fontColor = config.typography?.fontColor || '#000000';
                  textAlign = config.alignment?.horizontal || 'left';
                  verticalAlign = config.alignment?.vertical || 'top';
                  padding = config.padding || { top: 2, right: 2, bottom: 2, left: 2 };
                } else if (content.type === 'new-multi-line' && content.newMultiLineConfig) {
                  const config = content.newMultiLineConfig;
                  fontSize = config.typography?.fontSize || 12;
                  fontFamily = config.typography?.fontFamily || 'helvetica';
                  fontSizeUnit = config.typography?.fontSizeUnit || 'px';
                  fontColor = config.typography?.fontColor || '#000000';
                  textAlign = config.alignment?.horizontal || 'left';
                  verticalAlign = config.alignment?.vertical || 'top';
                  padding = config.padding || { top: 2, right: 2, bottom: 2, left: 2 };
                } else if (content.type === 'new-line-text' && content.newLineTextConfig) {
                  const config = content.newLineTextConfig;
                  fontSize = config.typography?.fontSize || 12;
                  fontFamily = config.typography?.fontFamily || 'helvetica';
                  fontSizeUnit = config.typography?.fontSizeUnit || 'px';
                  fontColor = config.typography?.fontColor || '#000000';
                  textAlign = config.alignment?.horizontal || 'left';
                  verticalAlign = config.alignment?.vertical || 'top';
                  padding = config.padding || { top: 2, right: 2, bottom: 2, left: 2 };
                } else if (content.type === 'new-washing-care-symbol' && content.newWashingCareSymbolConfig) {
                  const config = content.newWashingCareSymbolConfig;
                  fontSize = config.typography?.fontSize || 12;
                  fontFamily = config.typography?.fontFamily || 'helvetica';
                  fontSizeUnit = config.typography?.fontSizeUnit || 'px';
                  fontColor = config.typography?.fontColor || '#000000';
                  textAlign = config.alignment?.horizontal || 'left';
                  verticalAlign = config.alignment?.vertical || 'top';
                  padding = config.padding || { top: 2, right: 2, bottom: 2, left: 2 };
                } else {
                  const effectiveTypography = contentObj.typography || {};
                  const effectiveLayout = contentObj.layout || {};
                  fontSize = effectiveTypography.fontSize || 12;
                  fontFamily = effectiveTypography.fontFamily || 'helvetica';
                  fontSizeUnit = 'px';
                  fontColor = effectiveTypography.fontColor || '#000000';
                  textAlign = effectiveLayout.horizontalAlign || 'left';
                  verticalAlign = effectiveLayout.verticalAlign || 'top';
                  padding = effectiveLayout.padding || { top: 2, right: 2, bottom: 2, left: 2 };
                }

                // Convert font size to pixels if needed
                let fontSizeInPixels = fontSize;
                if (fontSizeUnit === 'pt') {
                  fontSizeInPixels = fontSize * 4/3;
                } else if (fontSizeUnit === 'mm') {
                  fontSizeInPixels = fontSize * 3.779527559;
                }

                // EXACT WEB REPLICATION: Match web view pixel-perfect
                // Web: scaledFontSize = Math.max(6, fontSize * zoom) where zoom = 1 for PDF
                const scaledFontSize = Math.max(6, fontSizeInPixels); // Exact web logic
                // Web: lineHeight = scaledFontSize * 1.2 (in pixels)
                const webLineHeightPx = scaledFontSize * 1.2; // Exact web logic

                // Convert web pixels to PDF units (1px = 0.264583mm at 96 DPI)
                const pdfFontSize = scaledFontSize * 0.75; // Convert px to pt for PDF
                const lineHeightMM = webLineHeightPx * 0.264583; // Convert px to mm

                pdf.setFontSize(pdfFontSize);
                pdf.setFont(fontFamily === 'Arial' ? 'helvetica' : fontFamily, 'normal');

                // Convert hex color to RGB exactly like web
                const hexToRgb = (hex: string) => {
                  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
                  return result ? {
                    r: parseInt(result[1], 16),
                    g: parseInt(result[2], 16),
                    b: parseInt(result[3], 16)
                  } : { r: 0, g: 0, b: 0 };
                };
                const color = hexToRgb(fontColor);
                pdf.setTextColor(color.r, color.g, color.b);

                // Calculate text area with exact padding like web view
                const paddingTop = padding.top || 0; // Use exact padding from content configuration
                const paddingRight = padding.right || 0;
                const paddingBottom = padding.bottom || 0;
                const paddingLeft = padding.left || 0;

                const textAreaWidth = Math.max(0, region.width - paddingLeft - paddingRight);
                const textAreaHeight = Math.max(0, region.height - paddingTop - paddingBottom);

                // Use pre-wrapped lines from N-split (already wrapped by canvas measureText)
                // Do NOT re-wrap with jsPDF's splitTextToSize - it uses different font metrics
                const wrappedText = displayText.split('\n');

                // Calculate max lines exactly like web view (with baseline offset)
                const fontSizeMM = pdfFontSize * 0.264583; // pt to mm
                const baselineOffsetMM = fontSizeMM * 0.8;
                const safeTextAreaHeight = Math.max(0, textAreaHeight - baselineOffsetMM);
                const maxLines = Math.max(0, Math.floor(safeTextAreaHeight / lineHeightMM));

                if (maxLines > 0) {
                  let displayLines = wrappedText;
                  if (displayLines.length > maxLines) {
                    displayLines = wrappedText.slice(0, maxLines);
                  }

                  // Calculate horizontal alignment exactly like web view
                  let textX = regionX + paddingLeft;
                  if (textAlign === 'center') {
                    textX = regionX + region.width / 2;
                  } else if (textAlign === 'right') {
                    textX = regionX + region.width - paddingRight;
                  }

                  // Calculate vertical alignment exactly like web view
                  // Web: startY = baseY + (region.y * scale) + paddingTopPx;
                  let startY = regionY + paddingTop;
                  if (verticalAlign === 'center') {
                    // Web: totalTextHeight = displayLines.length * lineHeight;
                    const totalTextHeight = displayLines.length * lineHeightMM;
                    // Web: startY = baseY + (region.y * scale) + (regionHeightPx - totalTextHeight) / 2;
                    startY = regionY + (region.height - totalTextHeight) / 2;
                  } else if (verticalAlign === 'bottom') {
                    const totalTextHeight = displayLines.length * lineHeightMM;
                    // Web: startY = baseY + (region.y * scale) + regionHeightPx - paddingBottomPx - totalTextHeight;
                    startY = regionY + region.height - paddingBottom - totalTextHeight;
                  }

                  // Handle washing care symbols or regular text
                  if (content.type === 'new-washing-care-symbol') {
                    // Render washing care symbols in PDF using configuration
                    const symbols = content.content?.symbols || ['b', 'G', '5', 'B', 'J'];

                    // Use configuration settings if available
                    const configIconSize = content.content?.iconSize || 8; // Default 8mm
                    const configPadding = content.content?.padding || { top: 2, left: 2, bottom: 2, right: 2 };
                    const configAlignment = content.content?.alignment || { horizontal: 'center', vertical: 'center' };

                    // Calculate available space after padding
                    const availableWidth = region.width - configPadding.left - configPadding.right;
                    const availableHeight = region.height - configPadding.top - configPadding.bottom;
                    const symbolSpacing = availableWidth / symbols.length;

                    // Calculate container position based on alignment
                    let containerX = regionX + configPadding.left;
                    let containerY = regionY + configPadding.top;

                    if (configAlignment.horizontal === 'center') {
                      containerX = regionX + (region.width / 2) - (availableWidth / 2);
                    } else if (configAlignment.horizontal === 'right') {
                      containerX = regionX + region.width - configPadding.right - availableWidth;
                    }

                    if (configAlignment.vertical === 'center') {
                      containerY = regionY + (region.height / 2) - (configIconSize / 2);
                    } else if (configAlignment.vertical === 'bottom') {
                      containerY = regionY + region.height - configPadding.bottom - configIconSize;
                    }

                    // For PDF, use the same font as canvas - embed Wash Care Symbols M54 font
                    symbols.forEach((symbol: string, symbolIndex: number) => {
                      const symbolX = containerX + symbolIndex * symbolSpacing + symbolSpacing / 2;
                      const symbolY = containerY + (configIconSize / 2);

                      // Use canvas rendering first for cross-computer compatibility
                      let fontUsed = false;
                      let canvasUsed = false;

                      // Force canvas rendering for better compatibility across computers
                      // Match SVG font size: configIconSize * 3.78px (1mm = 3.78px at 96 DPI)
                      const svgFontSizePx = configIconSize * 3.78; // Match SVG rendering exactly
                      const canvasImage = renderSymbolToCanvas(symbol, svgFontSizePx);
                      if (canvasImage) {
                        try {
                          // Calculate image size in mm to match SVG display exactly
                          // Canvas has padding of 0.2 * size on each side, so total canvas = size * 1.4
                          // To make the font-size pixels map to configIconSize mm, we need:
                          // Canvas total size in PDF = configIconSize * 1.4
                          const imageSize = configIconSize * 1.4; // Account for canvas padding (0.2 * size * 2)
                          const imageX = symbolX - imageSize / 2;
                          const imageY = symbolY - imageSize / 2;

                          // Add the canvas-rendered symbol as image
                          pdf.addImage(canvasImage, 'PNG', imageX, imageY, imageSize, imageSize);
                          canvasUsed = true;
                          console.log(`✅ Used canvas rendering for symbol: ${symbol} at ${imageSize}mm (1:1 SVG match)`);
                        } catch (error) {
                          console.error('❌ Canvas image failed:', error);
                          canvasUsed = false;
                        }
                      }

                      // Fallback to embedded font if canvas fails
                      if (!canvasUsed) {
                        try {
                          // Try to use the embedded Wash Care Symbols M54 font with configured size
                          try {
                            pdf.setFont('Wash Care Symbols M54', 'normal');
                          } catch {
                            pdf.setFont('WashCareSymbolsM54', 'normal');
                          }
                          pdf.setFontSize(configIconSize * 2.83); // Convert mm to points
                          pdf.setTextColor(0, 0, 0);
                          pdf.text(symbol, symbolX, symbolY, { align: 'center', baseline: 'middle' });
                          fontUsed = true;
                          console.log(`✅ Used embedded font for symbol: ${symbol}`);
                          // Reset font back to Arial/Helvetica for subsequent text rendering
                          pdf.setFont('helvetica', 'normal');
                        } catch (error) {
                          // Font not available
                          console.log(`⚠️ Font not available for symbol: ${symbol}, error:`, error);
                          fontUsed = false;
                        }
                      }

                      if (!fontUsed) {
                        // Try canvas rendering to capture the actual font symbols
                        // Match SVG font size: configIconSize * 3.78px (1mm = 3.78px at 96 DPI)
                        const svgFontSizePx = configIconSize * 3.78; // Match SVG rendering exactly
                        const canvasImage = renderSymbolToCanvas(symbol, svgFontSizePx);
                        if (canvasImage) {
                          try {
                            // Calculate image size in mm to match SVG display exactly
                            // Canvas total size in PDF = configIconSize * 1.4 (includes padding)
                            const imageSize = configIconSize * 1.4; // Account for canvas padding (0.2 * size * 2)
                            const imageX = symbolX - imageSize / 2;
                            const imageY = symbolY - imageSize / 2;

                            // Add the canvas-rendered symbol as image
                            pdf.addImage(canvasImage, 'PNG', imageX, imageY, imageSize, imageSize);
                            canvasUsed = true;
                            // console.log('✅ Used canvas rendering for symbol:', symbol);
                          } catch (error) {
                            console.error('❌ Canvas image failed:', error);
                            canvasUsed = false;
                          }
                        }
                      }

                      if (!fontUsed && !canvasUsed) {
                        // Fallback: Create vector shapes that match the canvas symbols exactly
                        pdf.setDrawColor(0, 0, 0);
                        pdf.setFillColor(255, 255, 255);
                        pdf.setLineWidth(0.4);

                      // Create shapes that exactly match the Wash Care Symbols M54 font appearance
                      switch (symbolIndex) {
                        case 0: // Washing (b) - Basin shape exactly like canvas font
                          // Draw basin with curved bottom like the font symbol
                          const basinWidth = configIconSize * 0.6;
                          const basinHeight = configIconSize * 0.4;
                          // Top rim
                          pdf.line(symbolX - basinWidth/2, symbolY - basinHeight/2, symbolX + basinWidth/2, symbolY - basinHeight/2);
                          // Left side
                          pdf.line(symbolX - basinWidth/2, symbolY - basinHeight/2, symbolX - basinWidth/3, symbolY + basinHeight/2);
                          // Right side
                          pdf.line(symbolX + basinWidth/2, symbolY - basinHeight/2, symbolX + basinWidth/3, symbolY + basinHeight/2);
                          // Bottom curve (approximated with line)
                          pdf.line(symbolX - basinWidth/3, symbolY + basinHeight/2, symbolX + basinWidth/3, symbolY + basinHeight/2);
                          break;
                        case 1: // Drying (G) - Square exactly like canvas font
                          const squareSize = configIconSize * 0.5;
                          pdf.rect(symbolX - squareSize/2, symbolY - squareSize/2, squareSize, squareSize, 'S');
                          break;
                        case 2: // Ironing (5) - Iron shape exactly like canvas font
                          const ironWidth = configIconSize * 0.5;
                          const ironHeight = configIconSize * 0.4;
                          // Iron base (rounded rectangle approximation)
                          pdf.ellipse(symbolX, symbolY + ironHeight/4, ironWidth/2, ironHeight/4, 'S');
                          // Iron point
                          pdf.lines([
                            [0, -ironHeight/2],
                            [ironWidth/4, -ironHeight/4],
                            [ironWidth/4, ironHeight/4],
                            [-ironWidth/4, ironHeight/4],
                            [-ironWidth/4, -ironHeight/4],
                            [0, -ironHeight/2]
                          ], symbolX, symbolY, [1, 1], 'S');
                          break;
                        case 3: // Bleaching (B) - Triangle exactly like canvas font
                          const triSize = configIconSize * 0.4;
                          pdf.triangle(symbolX, symbolY - triSize/2, symbolX + triSize/2, symbolY + triSize/2, symbolX - triSize/2, symbolY + triSize/2, 'S');
                          break;
                        case 4: // Professional (J) - Circle exactly like canvas font
                          const circleRadius = configIconSize * 0.25;
                          pdf.circle(symbolX, symbolY, circleRadius, 'S');
                          break;
                        }
                      } // End of fallback vector shapes
                    });
                  } else if (content.type === 'new-graphic' && content.content?.pdfData) {
                    // Render PDF graphic content in PDF export
                    console.log('🎨 Rendering graphic content to PDF:', content.content.pdfFileName);

                    const effectiveLayout = content.layout || {};
                    const padding = effectiveLayout.padding || { top: 0, right: 0, bottom: 0, left: 0 };

                    // Calculate available space after padding
                    const availableWidth = Math.max(0, region.width - padding.left - padding.right);
                    const availableHeight = Math.max(0, region.height - padding.top - padding.bottom);

                    // Calculate position with padding
                    const graphicX = regionX + padding.left;
                    const graphicY = regionY + padding.top;

                    try {
                      // Add the rendered PDF image to the PDF export
                      pdf.addImage(
                        content.content.pdfData,
                        'PNG',
                        graphicX,
                        graphicY,
                        availableWidth,
                        availableHeight,
                        undefined,
                        'FAST'
                      );
                      console.log('✅ Graphic content added to PDF:', {
                        x: graphicX,
                        y: graphicY,
                        width: availableWidth,
                        height: availableHeight
                      });
                    } catch (error) {
                      console.error('❌ Error adding graphic to PDF:', error);
                    }
                  } else if (content.type === 'new-comp-trans' || content.type === 'new-multi-line') {
                    // Render composition translation / multi-line text in PDF using configuration
                    const config = content.type === 'new-comp-trans' ? content.newCompTransConfig : content.newMultiLineConfig;

                    logExport(`🌐 MAIN REGION ${content.type.toUpperCase()} DEBUG:`, {
                      hasConfig: !!config,
                      configStructure: config ? JSON.stringify(config, null, 2) : 'NO CONFIG',
                      hasPadding: !!(config?.padding),
                      hasAlignment: !!(config?.alignment),
                      hasTypography: !!(config?.typography),
                      hasTextContent: !!(config?.textContent)
                    });

                    if (!config || !config.padding || !config.alignment || !config.typography) {
                      logExport('🌐 new-comp-trans missing configuration, skipping PDF render', {
                        config: config,
                        missingPadding: !config?.padding,
                        missingAlignment: !config?.alignment,
                        missingTypography: !config?.typography
                      });
                      return;
                    }

                    const configPadding = config.padding;
                    const configAlignment = config.alignment;
                    const configTypography = config.typography;

                    // Calculate available space after padding
                    const availableWidth = region.width - configPadding.left - configPadding.right;
                    const availableHeight = region.height - configPadding.top - configPadding.bottom;

                    // Calculate text position based on alignment
                    let textX = regionX + configPadding.left;
                    let textY = regionY + configPadding.top;

                    if (configAlignment.horizontal === 'center') {
                      textX = regionX + (region.width / 2);
                    } else if (configAlignment.horizontal === 'right') {
                      textX = regionX + region.width - configPadding.right;
                    }

                    if (configAlignment.vertical === 'center') {
                      textY = regionY + (region.height / 2);
                    } else if (configAlignment.vertical === 'bottom') {
                      textY = regionY + region.height - configPadding.bottom;
                    }

                    // Set font and render text with proper wrapping
                    pdf.setFont('helvetica', 'normal');

                    let fontSize = configTypography.fontSize;
                    if (configTypography.fontSizeUnit === 'pt') {
                      fontSize = fontSize * 0.352778; // Convert pt to mm
                    } else if (configTypography.fontSizeUnit === 'px') {
                      fontSize = fontSize * 0.264583; // Convert px to mm
                    }
                    pdf.setFontSize(fontSize * 2.83); // Convert mm to points for jsPDF
                    pdf.setTextColor(0, 0, 0);

                    const textContent = content.type === 'new-comp-trans'
                      ? (content.newCompTransConfig?.textContent?.generatedText || 'Composition Translation')
                      : (content.content?.text || 'Multiple Line');

                    // UNICODE DETECTION: Check if text contains Unicode characters that need canvas rendering
                    // OR force canvas rendering for new-multi-line to preserve exact font sizing
                    const hasUnicodeChars = /[^\x00-\x7F]/.test(textContent) || content.type === 'new-multi-line'; // Detects non-ASCII characters OR new-multi-line

                    logExport(`🌐 Unicode detection:`, {
                      hasUnicodeChars: hasUnicodeChars,
                      textLength: textContent.length,
                      textPreview: textContent.substring(0, 100) + '...',
                      willUseCanvasRendering: hasUnicodeChars
                    });

                    // Use EXACT same text wrapping logic as canvas rendering
                    // Match canvas calculation: availableWidthPx = Math.max(0, regionWidthPx - paddingLeftPx - paddingRightPx)
                    const availableWidthPx = Math.max(0, availableWidth * 3.779527559); // Convert mm to px
                    const availableHeightPx = Math.max(0, availableHeight * 3.779527559);

                    // Match canvas font size calculation (no zoom factor in PDF)
                    let fontSizeForProcessing = configTypography.fontSize;
                    if (configTypography.fontSizeUnit === 'pt') {
                      fontSizeForProcessing = configTypography.fontSize * 4/3; // Convert points to pixels
                    } else if (configTypography.fontSizeUnit === 'mm') {
                      fontSizeForProcessing = configTypography.fontSize * 3.779527559; // Convert mm to pixels
                    }
                    const scaledFontSize = Math.max(6, fontSizeForProcessing); // No zoom in PDF, but keep minimum

                    // 🎯 SELECTIVE CTP METHOD: Use canvas rendering for Unicode text preservation
                    // If text contains Unicode characters, use canvas rendering to preserve original characters
                    // Otherwise use text rendering for copyable text
                    const motherName = mother.name || '';
                    const motherNumber = parseInt(motherName.match(/Mother_(\d+)/)?.[1] || '1');

                    if (hasUnicodeChars) {
                      logExport(`🎯 Using canvas method for Unicode text preservation in ${motherName} - main region as image`);

                      // Create a temporary canvas for rendering international text
                      const tempCanvas = document.createElement('canvas');
                      const tempCtx = tempCanvas.getContext('2d');

                      if (!tempCtx) {
                        console.error('Failed to get canvas context, falling back to regular text rendering');
                        // Fallback to regular text rendering
                        const wrappedResult = processChildRegionTextWrapping(
                          textContent,
                          availableWidthPx,
                          availableHeightPx,
                          scaledFontSize,
                          configTypography.fontFamily,
                          config.lineBreakSettings?.lineBreakSymbol || config.lineBreak?.symbol || '\n',
                          config.lineBreakSettings?.lineSpacing || config.lineBreak?.lineSpacing || 1.2
                        );

                        const lineHeightMM = fontSize * (config.lineBreakSettings?.lineSpacing || config.lineBreak?.lineSpacing || 1.2);
                        const alignOption = configAlignment.horizontal === 'center' ? 'center' :
                                           configAlignment.horizontal === 'right' ? 'right' : 'left';

                        wrappedResult.lines.forEach((line: string, lineIndex: number) => {
                          const lineY = textY + (lineIndex * lineHeightMM);
                          pdf.text(line.trim(), textX, lineY, { align: alignOption });
                        });
                        return;
                      }

                      // Set canvas size to match the region exactly for pixel-perfect rendering
                      const dpiScale = 2; // Higher DPI for quality
                      tempCanvas.width = availableWidthPx * dpiScale;
                      tempCanvas.height = availableHeightPx * dpiScale;
                      tempCtx.scale(dpiScale, dpiScale);

                      // Fill with white background to match screen display
                      tempCtx.fillStyle = '#FFFFFF';
                      tempCtx.fillRect(0, 0, availableWidthPx, availableHeightPx);

                      // Set font and style to EXACTLY match the SVG rendering
                      tempCtx.font = `${scaledFontSize}px ${configTypography.fontFamily}`;
                      tempCtx.fillStyle = configTypography.color || '#000000';
                      tempCtx.textAlign = configAlignment.horizontal === 'center' ? 'center' :
                                        configAlignment.horizontal === 'right' ? 'right' : 'left';
                      tempCtx.textBaseline = 'top'; // Critical: match SVG text baseline

                      // Use the EXACT same text wrapping as displayed on screen (preserve original Unicode)
                      const wrappedResult = processChildRegionTextWrapping(
                        textContent, // Use original text with Unicode characters preserved
                        availableWidthPx,
                        availableHeightPx,
                        scaledFontSize,
                        configTypography.fontFamily,
                        config.lineBreakSettings?.lineBreakSymbol || config.lineBreak?.symbol || '\n',
                        config.lineBreakSettings?.lineSpacing || config.lineBreak?.lineSpacing || 1.2
                      );

                      // Render each line with EXACT positioning to match screen including vertical alignment
                      const lineHeightPx = scaledFontSize * (config.lineBreakSettings?.lineSpacing || config.lineBreak?.lineSpacing || 1.2);
                      const totalTextHeight = wrappedResult.lines.length * lineHeightPx;

                      // Calculate vertical starting position based on alignment
                      let startY = 0; // Default: top
                      if (configAlignment.vertical === 'center') {
                        startY = (availableHeightPx - totalTextHeight) / 2;
                      } else if (configAlignment.vertical === 'bottom') {
                        startY = availableHeightPx - totalTextHeight;
                      }

                      wrappedResult.lines.forEach((line: string, lineIndex: number) => {
                        const lineY = startY + (lineIndex * lineHeightPx);
                        let lineX = 0;
                        if (configAlignment.horizontal === 'center') {
                          lineX = availableWidthPx / 2;
                        } else if (configAlignment.horizontal === 'right') {
                          lineX = availableWidthPx;
                        }
                        tempCtx.fillText(line, lineX, lineY);
                      });

                      // Convert canvas to high-quality PNG image
                      const imgData = tempCanvas.toDataURL('image/png', 1.0);
                      const imgWidthMM = availableWidth;
                      const imgHeightMM = availableHeight;

                      // Place canvas at content area start point (not textX which is center-aligned)
                      const contentStartX = regionX + configPadding.left;
                      const contentStartY = regionY + configPadding.top;
                      pdf.addImage(imgData, 'PNG', contentStartX, contentStartY, imgWidthMM, imgHeightMM, undefined, 'FAST');

                      // console.log('📋 Exact canvas-to-PDF rendering complete (pixel-perfect match)');

                      // Create selectable text overlay for webpage interaction
                      const regionBounds = {
                        x: textX * (96 / 25.4), // Convert mm to pixels (96 DPI)
                        y: textY * (96 / 25.4),
                        width: availableWidth * (96 / 25.4),
                        height: availableHeight * (96 / 25.4),
                        fontSize: fontSize * (96 / 25.4) / 2.83, // Convert back to screen pixels
                        fontFamily: configTypography.fontFamily
                      };
                      createSelectableTextOverlay(`main-${region.id}`, textContent, regionBounds);

                    } else {
                      // Use normal text rendering for ASCII-only text (copyable text)
                      logExport(`📝 Using text method for ${motherName} - main region copyable text (no Unicode chars)`);
                      const wrappedResult = processChildRegionTextWrapping(
                        textContent, // Use original text (safe since no Unicode chars detected)
                        availableWidthPx,
                        availableHeightPx,
                        scaledFontSize,
                        configTypography.fontFamily,
                        content.newCompTransConfig?.lineBreakSettings?.lineBreakSymbol || '\n',
                        content.newCompTransConfig?.lineBreakSettings?.lineSpacing || 1.2
                      );

                      const lineHeightMM = fontSize * (content.newCompTransConfig?.lineBreakSettings?.lineSpacing || 1.2);
                      const alignOption = configAlignment.horizontal === 'center' ? 'center' :
                                         configAlignment.horizontal === 'right' ? 'right' : 'left';

                      // console.log('🖨️ PDF Composition Text Rendering (Main) - DETAILED DEBUG:', {
                      //   originalText: textContent,
                      //   availableWidthMm: availableWidth,
                      //   availableHeightMm: availableHeight,
                      //   availableWidthPx: availableWidthPx,
                      //   availableHeightPx: availableHeightPx,
                      //   fontSizeForProcessing: fontSizeForProcessing,
                      //   scaledFontSize: scaledFontSize,
                      //   fontSizeUnit: configTypography.fontSizeUnit,
                      //   wrappedLines: wrappedResult.lines,
                      //   lineCount: wrappedResult.lines.length,
                      //   hasOverflow: wrappedResult.hasOverflow,
                      //   padding: configPadding
                      // });

                      wrappedResult.lines.forEach((line: string, lineIndex: number) => {
                        const lineY = textY + (lineIndex * lineHeightMM);
                        pdf.text(line.trim(), textX, lineY, { align: alignOption });
                      });
                    }
                  } else {
                    // 🎯 SELECTIVE RENDERING: Use different methods based on mother type
                    const motherName = mother.name || '';
                    const motherNumber = parseInt(motherName.match(/Mother_(\d+)/)?.[1] || '1');
                    const useCanvasMethod = motherNumber >= 3; // Canvas method only for Mother 3+

                    if (useCanvasMethod) {
                      console.log(`🎯 Using canvas method for ${motherName} (Mother ${motherNumber}) - main region as image`);

                    // Create simple canvas
                    const canvas = document.createElement('canvas');
                    const ctx = canvas.getContext('2d');

                    if (ctx) {
                      // Simple canvas size
                      const width = (region.width - paddingLeft - paddingRight) * 4;
                      const height = (region.height - paddingTop - paddingBottom) * 4;
                      canvas.width = width;
                      canvas.height = height;

                      // White background
                      ctx.fillStyle = 'white';
                      ctx.fillRect(0, 0, width, height);

                      // Simple font setup
                      ctx.font = `${fontSize * 4}px ${fontFamily}`;
                      ctx.fillStyle = 'black';
                      ctx.textAlign = textAlign === 'center' ? 'center' : textAlign === 'right' ? 'right' : 'left';

                      // Draw text lines
                      displayLines.forEach((line: string, i: number) => {
                        const y = (i + 1) * lineHeightMM * 4;
                        let x = 0;
                        if (textAlign === 'center') x = width / 2;
                        else if (textAlign === 'right') x = width;
                        ctx.fillText(line, x, y);
                      });

                      // Place canvas at content area start point (not textX which is center-aligned)
                      const imgData = canvas.toDataURL('image/png');
                      const contentStartX = regionX + paddingLeft;
                      const contentStartY = regionY + paddingTop;
                      pdf.addImage(imgData, 'PNG', contentStartX, contentStartY,
                        region.width - paddingLeft - paddingRight,
                        region.height - paddingTop - paddingBottom);
                    } else {
                      // Simple fallback for canvas method
                      displayLines.forEach((line: string, lineIndex: number) => {
                        const textY = startY + (lineIndex + 1) * lineHeightMM;
                        const align = textAlign === 'center' ? 'center' : textAlign === 'right' ? 'right' : 'left';
                        pdf.text(line, textX, textY, { align: align });
                      });
                    }
                  } else {
                    // Use normal text rendering for Mother 1 & 2 (copyable text)
                      console.log(`📝 Using text method for ${motherName} (Mother ${motherNumber}) - main region copyable text`);

                      displayLines.forEach((line: string, lineIndex: number) => {
                        const textY = startY + (lineIndex + 1) * lineHeightMM;
                        const align = textAlign === 'center' ? 'center' : textAlign === 'right' ? 'right' : 'left';
                        pdf.text(line, textX, textY, { align: align });
                      });
                    }
                  }

                  // Draw content padding boundaries (green dotted lines) if supporting lines are enabled
                  if (showSupportingLines && !onlyPreview && (paddingTop > 0 || paddingRight > 0 || paddingBottom > 0 || paddingLeft > 0)) {
                    pdf.setDrawColor(76, 175, 80); // Green color (#4CAF50)
                    pdf.setLineWidth(0.2); // Fine style - very thin lines

                    console.log('🔍 PDF Content Padding Debug:', {
                      regionName: region.name,
                      contentType: content.type,
                      paddingTop, paddingRight, paddingBottom, paddingLeft,
                      regionX, regionY, regionWidth: region.width, regionHeight: region.height
                    });

                    // Top padding line
                    if (paddingTop > 0) {
                      pdf.setLineDashPattern([1, 1], 0.1); // Fine dotted with offset
                      pdf.line(regionX + paddingLeft, regionY + paddingTop, regionX + region.width - paddingRight, regionY + paddingTop);
                      console.log('✅ Drew TOP padding line');
                    }
                    // Bottom padding line - FORCE DRAW if any other padding exists
                    if (paddingBottom > 0 || (paddingTop > 0 || paddingLeft > 0 || paddingRight > 0)) {
                      pdf.setLineDashPattern([1, 1], 0.3); // Different offset to prevent overlap
                      const bottomY = regionY + region.height - (paddingBottom > 0 ? paddingBottom : 3); // Use 3mm default if paddingBottom is 0
                      pdf.line(regionX + paddingLeft, bottomY, regionX + region.width - paddingRight, bottomY);
                      console.log('✅ Drew BOTTOM padding line at Y:', bottomY, 'paddingBottom:', paddingBottom);
                    } else {
                      console.log('❌ SKIPPED BOTTOM padding line - no padding at all');
                    }
                    // Left padding line
                    if (paddingLeft > 0) {
                      pdf.setLineDashPattern([1, 1], 0.5); // Different offset for vertical lines
                      pdf.line(regionX + paddingLeft, regionY + paddingTop, regionX + paddingLeft, regionY + region.height - paddingBottom);
                      console.log('✅ Drew LEFT padding line');
                    }
                    // Right padding line
                    if (paddingRight > 0) {
                      pdf.setLineDashPattern([1, 1], 0.7); // Different offset to prevent overlap
                      pdf.line(regionX + region.width - paddingRight, regionY + paddingTop, regionX + region.width - paddingRight, regionY + region.height - paddingBottom);
                      console.log('✅ Drew RIGHT padding line');
                    }

                    pdf.setLineDashPattern([], 0); // Reset to solid line
                  }
                }
              }
            }
          }
        });
      });

      // Check if this is multi-page mode (only for order preview, not manual PDF generation)
      const orderData = sessionStorage.getItem('__order_preview_data__');
      const multiPageMode = isOrderPreview && orderData ? JSON.parse(orderData).multiPageMode : false;
      const currentLineIndex = orderData ? JSON.parse(orderData).currentLineIndex : 0;
      const totalLines = orderData ? JSON.parse(orderData).totalLines : 1;

      console.log('PDF_MODE_CHECK:', {
        isOrderPreview,
        hasOrderData: !!orderData,
        multiPageMode,
        currentLineIndex,
        totalLines
      });

      if (multiPageMode) {
        // Multi-page mode: Send PDF data as base64 to parent for combining
        console.log(`📄 Generating page ${currentLineIndex + 1}/${totalLines} for multi-page PDF...`);

        const pdfData = pdf.output('datauristring'); // Get PDF as base64 data URI

        logExport(`✅ Generated PDF page ${currentLineIndex + 1}/${totalLines}`, {
          pageNumber: currentLineIndex + 1,
          totalPages: totalLines,
          paperSize: paperSize,
          paperDimensions: `${paperWidthMM}×${paperHeightMM}mm`
        });

        // Send PDF data to parent window
        console.log(`📤 Sending PDF page ${currentLineIndex + 1}/${totalLines} to parent window`);
        console.log(`📊 Actual mother count for this page: ${mothers.length}`);
        window.parent.postMessage({
          type: 'PDF_PAGE_GENERATED',
          pageNumber: currentLineIndex + 1,
          totalPages: totalLines,
          pdfData: pdfData,
          actualMotherCount: mothers.length, // Add actual rendered mother count
          paperSize: paperSize,
          paperWidth: paperWidthMM,
          paperHeight: paperHeightMM,
          orientation: orientation
        }, '*');
      } else {
        // Single page mode: Save immediately
        const filePrefix = isOrderPreview ? 'Order_Preview' : (isProjectMode ? 'Project_Everything' : 'AllMothers');
        const fileName = `${filePrefix}_${paperSize}_${new Date().toISOString().slice(0, 10)}.pdf`;
        pdf.save(fileName);

        logExport(`✅ Generated PDF: ${fileName}`, {
          fileName: fileName,
          paperSize: paperSize,
          motherCount: mothers.length,
          paperDimensions: `${paperWidthMM}×${paperHeightMM}mm`,
          utilization: `${(bestUtilization * 100).toFixed(1)}%`
        });

        // Export all debug logs for easy copying
        exportAllLogs();

        if (isOrderPreview) {
          // Send success message to parent window
          console.log('📤 Sending PDF_GENERATED message to parent window');
          window.parent.postMessage({
            type: 'PDF_GENERATED',
            fileName: fileName
          }, '*');
        }
      }

      if (!multiPageMode) {
        // Show notification for manual PDF generation
        const notificationText = isProjectMode
          ? `✅ Generated PDF with everything on canvas (${mothers.length} mothers) on ${paperSize}`
          : `✅ Generated single PDF with ${mothers.length} mothers on ${paperSize}`;
        setNotification(notificationText);
        setTimeout(() => setNotification(null), 3000);
      }

    } catch (error) {
      logExport('❌ Error generating PDF:', { error: error instanceof Error ? error.message : String(error) });
      exportAllLogs();
      console.error('❌ Error generating PDF:', error);

      // Check if this is order preview mode
      const urlParams = new URLSearchParams(window.location.search);
      const isOrderPreview = urlParams.get('autoGeneratePDF') === 'true';

      if (isOrderPreview) {
        // Send error message to parent window
        window.parent.postMessage({
          type: 'PDF_ERROR',
          error: error instanceof Error ? error.message : 'Unknown error'
        }, '*');
      } else {
        alert('❌ Error generating PDF. Please try again.');
      }
    }
  };

